INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué es una estadía?','Una estadía es un periodo de formación práctica que realizan los estudiantes en una empresa, institución u organización relacionada con su programa educativo. Durante este proceso, el estudiante desarrolla un proyecto real que le permite aplicar los conocimientos y habilidades adquiridos durante su formación académica. En la UTTT, la estadía de TSU se realiza en sexto cuatrimestre y la de Ingeniería o Licenciatura en décimo cuatrimestre. Para más información o asesoría, puedes acudir al Departamento de Estadías e Inserción Laboral o comunicarte al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["que es una estadia","que son las estadias","en que consiste una estadia","para que sirven las estadias","que hago en una estadia","que es la estadia profesional","que significa hacer estadias","explicame que es una estadia","informacion sobre estadias","como funcionan las estadias","para que hago estadias","que actividades se realizan en estadias","que se hace durante una estadia","cual es el objetivo de las estadias","que debo hacer en mi estadia","de que trata la estadia","estadias profesionales","proyecto de estadia","practicas profesionales y estadias","que es una estadia universitaria","como son las estadias","para que me sirven las estadias","que aprendere en estadias","estadias de tsu","estadias de ingenieria","estadias de licenciatura","en que cuatrimestre son las estadias","como se realizan las estadias","quiero informacion de estadias","que necesito para estadias","como empezar mis estadias","cual es la finalidad de las estadias","porque debo hacer estadias","estadias en empresas","trabajo de estadia","proceso de estadias","como hacer una estadia","que es el periodo de estadia","dudas sobre estadias","orientacion sobre estadias"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué documentos necesito para realizar mi estadía?','Durante el proceso de estadía se solicitan diversos documentos que permiten dar seguimiento y formalizar las actividades realizadas por el estudiante. Entre los principales documentos se encuentran: Carta de aceptación, Plan de trabajo, Carta compromiso, Carta de acuerdos, Minuta de acuerdos, Evaluación de estadía, Reporte final y Carta de terminación. Los formatos correspondientes pueden consultarse y descargarse en la sección "Formatos de Estadías" del siguiente enlace: https://uttt.edu.mx/ServiciosDeVinculacion/Alumnos/Es.Estadia.html. Te recomendamos mantener comunicación constante con tu asesor académico y con el Departamento de Estadías e Inserción Laboral para conocer los formatos vigentes y fechas de entrega. Para más información puedes comunicarte al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["que documentos necesito para mi estadia","documentos para estadias","requisitos documentales de estadia","papeles para estadias","que debo entregar en estadias","documentacion de estadias","cuales son los documentos de estadia","formatos de estadias","que formatos necesito para estadia","expediente de estadia","carta de aceptacion estadia","reporte final de estadia","evaluacion de estadia","carta compromiso estadia","plan de trabajo estadia","minuta de acuerdos estadia","carta de acuerdos estadia","carta de terminacion estadia","documentos requeridos para estadia","tramites de estadias","que necesito para iniciar mi estadia","documentos para empezar estadias","archivos de estadias","evidencias de estadias","proceso documental de estadias","requisitos para realizar estadias","que entregables tiene la estadia","que formatos debo llenar para estadia","lista de documentos de estadia","que necesito entregar en vinculacion","documentos de practicas profesionales","papeleria para estadias","como armar mi expediente de estadia","documentos obligatorios de estadia","que documentos pide vinculacion","requisitos de vinculacion para estadias","cuales son los entregables de estadia","que debo presentar para mi estadia","proceso de documentos para estadia","donde consigo los formatos de estadia"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Puedo utilizar inteligencia artificial en mi reporte de estadía?','Sí. La inteligencia artificial puede utilizarse como una herramienta de apoyo en la elaboración del reporte de estadía para actividades como corrección ortográfica y gramatical, organización de contenidos, elaboración de resúmenes, apoyo en referencias bibliográficas y otras tareas complementarias. Sin embargo, el estudiante sigue siendo el responsable del contenido presentado y deberá respetar los lineamientos institucionales sobre el uso ético de la inteligencia artificial. Se recomienda consultar los lineamientos vigentes de estadía y mantener comunicación con el asesor académico para resolver cualquier duda relacionada con su uso.','alumnos',true,'["puedo usar chatgpt en mi estadia","puedo usar inteligencia artificial en mi estadia","puedo usar ia en mi reporte","esta permitido usar chatgpt","puedo apoyarme de chatgpt","puedo usar gemini en mi reporte","puedo usar copilot en mi estadia","puedo usar herramientas de ia","esta permitido usar inteligencia artificial","la universidad permite usar ia","puedo redactar mi reporte con ia","puedo usar chatgpt para mi reporte final","puedo usar ia para hacer mi reporte","chatgpt esta permitido","puedo apoyarme de gemini","puedo usar claude","puedo usar deepseek","la ia esta permitida en estadias","puedo usar inteligencia artificial para redactar","puedo usar ia para corregir mi reporte","puedo usar chatgpt para corregir ortografia","me pueden reprobar por usar ia","esta prohibido usar chatgpt","que usos de ia estan permitidos","puedo usar inteligencia artificial para resumir","puedo usar ia para formato apa","como puedo usar ia en mi estadia","que herramientas de ia puedo usar","puedo usar chatgpt para referencias","puedo usar gemini para mi proyecto","puedo usar ia en mi trabajo de estadia","puedo hacer mi reporte con chatgpt","chatgpt para reporte de estadia","uso de inteligencia artificial en estadias","reglamento de ia en estadias","politica de uso de ia","puedo utilizar herramientas generativas","puedo usar asistentes de inteligencia artificial","puedo usar modelos de lenguaje","puedo apoyarme de una ia","esta permitido usar herramientas digitales de ia","puedo usar chatgpt para organizar mi reporte","puedo usar ia para mejorar redaccion","puedo usar inteligencia artificial para investigar","puedo usar ia para generar contenido","puedo usar chatgpt en el reporte final","uso correcto de ia en estadias","lineamientos de ia en estadias","normas de uso de ia","puedo usar inteligencia artificial generativa"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué usos de inteligencia artificial están permitidos en mi reporte de estadía?','De acuerdo con los lineamientos institucionales, la inteligencia artificial puede utilizarse como apoyo para la planeación y organización de ideas, mejora de ortografía, gramática y redacción, elaboración de resúmenes, apoyo en referencias bibliográficas conforme a normas APA, búsqueda preliminar de antecedentes teóricos, organización de apartados del documento, elaboración de diagramas o esquemas preliminares y preparación de instrumentos auxiliares. Toda la información generada deberá ser revisada, validada y complementada por el estudiante, quien conserva la responsabilidad total sobre el contenido presentado en el reporte final de estadía.','alumnos',true,'["que usos de ia estan permitidos","que puedo hacer con inteligencia artificial","para que puedo usar chatgpt en mi estadia","que puedo hacer con chatgpt","usos permitidos de inteligencia artificial","que herramientas de ia puedo usar","como puedo usar ia en mi reporte","para que sirve la ia en estadias","puedo usar chatgpt para corregir ortografia","puedo usar ia para mejorar redaccion","puedo usar chatgpt para resumir","puedo usar gemini para resumir","puedo usar copilot para mi reporte","puedo usar ia para formato apa","puedo usar inteligencia artificial para referencias","puedo usar chatgpt para referencias bibliograficas","puedo usar ia para organizar ideas","puedo usar chatgpt para organizar mi reporte","puedo usar inteligencia artificial para esquemas","puedo usar ia para diagramas","puedo usar chatgpt para diagramas","puedo usar ia para mapas de procesos","puedo usar ia para hacer tablas","puedo usar inteligencia artificial para abstracts","puedo usar chatgpt para abstracts","puedo usar ia para sintesis","puedo usar ia para resumenes","puedo usar inteligencia artificial para antecedentes teoricos","puedo usar ia para buscar informacion","puedo usar chatgpt para investigar","puedo usar ia para buscar bibliografia","puedo usar chatgpt para bibliografia","puedo usar inteligencia artificial para estructura del reporte","puedo usar ia para organizar capitulos","que actividades estan permitidas con ia","que cosas puedo hacer con inteligencia artificial","para que esta permitida la ia","como se permite usar la ia","uso correcto de chatgpt","uso correcto de inteligencia artificial","que apoyos puede dar la ia","chatgpt permitido en estadias","gemini permitido en estadias","copilot permitido en estadias","deepseek permitido en estadias","claude permitido en estadias","uso etico de ia en estadias","que tareas puedo realizar con ia","para que puedo apoyarme en una ia","que permite la universidad sobre ia"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué usos de inteligencia artificial están prohibidos en mi reporte de estadía?','De acuerdo con los lineamientos institucionales, no está permitido utilizar inteligencia artificial para redactar de forma total o mayoritaria el Reporte Final de Estadía, generar más del 30% del contenido textual, inventar o alterar datos, tablas, indicadores, encuestas, evidencias o resultados, simular actividades que no se hayan realizado, crear objetivos, metodologías, conclusiones o recomendaciones sin sustento real, incluir referencias bibliográficas falsas o no verificadas, presentar como propias actividades o análisis generados automáticamente, omitir la declaración del uso de inteligencia artificial, compartir información confidencial de la empresa o de la universidad en herramientas públicas de IA, ni utilizar estas herramientas para evadir la comprensión o defensa del proyecto desarrollado. El uso indebido de inteligencia artificial puede considerarse una falta a la honestidad académica. Si tienes dudas sobre el uso correcto de estas herramientas, puedes comunicarte al correo practicas@uttt.edu.mx, al teléfono 773 732 9100 extensiones 209 o 108, o acudir con tu Dirección de Carrera para recibir orientación.','alumnos',true,'["que usos de ia estan prohibidos","que no puedo hacer con chatgpt en mi estadia","que esta prohibido con inteligencia artificial","puedo hacer todo mi reporte con chatgpt","puedo hacer mi estadia con chatgpt","chatgpt puede escribir todo mi reporte","puedo copiar y pegar lo que me da chatgpt","puedo usar ia para redactar todo el reporte","esta prohibido usar chatgpt","que cosas no puedo hacer con ia","puedo inventar datos con chatgpt","puedo generar resultados con ia","puedo crear encuestas falsas con ia","puedo inventar indicadores con inteligencia artificial","puedo usar ia para hacer mis conclusiones","puedo usar chatgpt para mi metodologia","puedo usar ia para escribir resultados","puedo usar inteligencia artificial para todo el reporte","puedo generar mas del 30 por ciento del reporte con ia","puedo presentar como mio contenido generado por ia","puedo omitir que use chatgpt","es obligatorio declarar el uso de ia","puedo ocultar que use inteligencia artificial","puedo subir informacion de mi empresa a chatgpt","puedo compartir informacion confidencial con ia","puedo cargar documentos de mi empresa en chatgpt","puedo usar datos internos de la empresa en ia","puedo generar referencias falsas con ia","puedo inventar bibliografia con chatgpt","puedo poner fuentes que no consulte","puedo usar ia para hacer objetivos","puedo usar ia para hacer recomendaciones","puedo usar ia para hacer el desarrollo del reporte","puedo generar actividades que no hice","puedo simular actividades con ia","puedo alterar resultados con inteligencia artificial","puedo modificar evidencias con ia","puedo crear tablas falsas con chatgpt","puedo generar capturas falsas","que considera la universidad como uso indebido de ia","que acciones estan prohibidas con ia","que dice el reglamento sobre chatgpt","que limita el uso de inteligencia artificial","puedo hacer mi proyecto completo con ia","puedo hacer mi reporte final con inteligencia artificial","puedo usar gemini para escribir todo mi reporte","puedo usar copilot para hacer mi estadia","puedo usar deepseek para generar mi reporte completo","puedo usar claude para redactar todo el documento","restricciones del uso de ia en estadias"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');   
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Es obligatorio declarar el uso de inteligencia artificial en mi reporte de estadía?','Sí. De acuerdo con los lineamientos institucionales, todo uso de herramientas de inteligencia artificial debe declararse de manera obligatoria en el Reporte Final de Estadía, incluso cuando su uso haya sido únicamente para corrección de estilo, organización de ideas, apoyo en referencias bibliográficas, elaboración de resúmenes o actividades similares. El reporte deberá incluir un apartado denominado "Declaración de uso de herramientas de Inteligencia Artificial", donde se indique la herramienta utilizada, la finalidad de su uso, los prompts o instrucciones empleadas y la forma en que se validó la información generada. Asimismo, se recomienda conservar evidencia como capturas de pantalla, prompts y respuestas generadas para una posible revisión académica. Si tienes dudas sobre cómo realizar esta declaración, puedes comunicarte al correo practicas@uttt.edu.mx, al teléfono 773 732 9100 extensiones 209 o 108, o acudir con tu Dirección de Carrera para recibir orientación.','alumnos',true,'["es obligatorio declarar el uso de ia","tengo que declarar chatgpt","debo declarar inteligencia artificial","debo decir que use chatgpt","es obligatorio reportar el uso de ia","tengo que mencionar que use chatgpt","debo informar que use inteligencia artificial","como declaro el uso de ia","como reporto el uso de chatgpt","como mencionar inteligencia artificial en mi reporte","donde pongo que use chatgpt","donde declaro el uso de ia","debo citar chatgpt","tengo que citar inteligencia artificial","como cito chatgpt en mi reporte","como cito una herramienta de ia","debo mencionar que use gemini","debo mencionar que use copilot","debo mencionar que use deepseek","debo mencionar que use claude","puedo omitir que use chatgpt","puedo ocultar que use inteligencia artificial","que pasa si no declaro la ia","es necesario declarar el uso de ia","es obligatorio indicar que use inteligencia artificial","tengo que poner una declaracion de ia","declaracion de uso de inteligencia artificial","apartado de inteligencia artificial","apartado de ia en estadias","formato de declaracion de ia","que debe contener la declaracion de ia","debo guardar evidencia del uso de ia","debo guardar capturas de chatgpt","debo guardar los prompts","tengo que anexar los prompts","debo conservar respuestas de ia","como documentar el uso de inteligencia artificial","como registrar el uso de ia","es obligatorio informar que use chatgpt","es obligatorio informar que use gemini","es obligatorio informar que use copilot","debo especificar que herramienta use","tengo que indicar los prompts utilizados","como hago la declaracion de chatgpt","uso de inteligencia artificial en estadias","normas para declarar ia","requisitos para declarar inteligencia artificial","politica de declaracion de ia","debo incluir la ia en mi reporte","declarar herramientas de inteligencia artificial"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué consecuencias puede tener el uso indebido de inteligencia artificial en mi reporte de estadía?','El uso indebido o no declarado de herramientas de inteligencia artificial puede considerarse una falta a la honestidad académica, equiparable al plagio. Algunas conductas que pueden generar consecuencias académicas incluyen presentar como propio contenido generado mayoritariamente por IA, omitir la declaración de uso, inventar datos, resultados o evidencias, utilizar referencias falsas, compartir información confidencial o presentar actividades no realizadas. Dependiendo de la gravedad del caso y de la valoración de las instancias competentes, las consecuencias pueden incluir la corrección del reporte, una calificación reprobatoria en la estadía con posibilidad de nueva evaluación, el rechazo definitivo del Reporte Final de Estadía o la aplicación de sanciones académicas previstas en la normativa institucional. Si tienes dudas sobre el uso correcto de herramientas de inteligencia artificial, puedes comunicarte al correo practicas@uttt.edu.mx, al teléfono 773 732 9100 extensiones 209 o 108, o acudir con tu Dirección de Carrera para recibir orientación.','alumnos',true,'["me pueden reprobar por usar chatgpt","que pasa si uso mal la ia","consecuencias de usar inteligencia artificial","sanciones por usar chatgpt","castigos por usar ia","que pasa si no declaro chatgpt","que pasa si oculto que use ia","me pueden rechazar el reporte","puedo perder mi estadia por usar ia","faltas por uso de inteligencia artificial","plagio con inteligencia artificial","uso indebido de chatgpt","que pasa si invento datos con ia","consecuencias de no declarar la ia","me pueden sancionar por usar gemini","me pueden sancionar por usar copilot","me pueden reprobar la estadia","rechazo del reporte de estadia","uso no autorizado de ia","reglamento de sanciones por ia","que pasa si hago mi reporte con chatgpt","puedo ser sancionado por usar inteligencia artificial","que consecuencias tiene usar ia incorrectamente","me pueden castigar por usar chatgpt","que pasa si presento contenido generado por ia","que ocurre si uso inteligencia artificial indebidamente","puedo reprobar por no declarar la ia","que pasa si invento resultados con chatgpt","que pasa si genero referencias falsas","puedo perder mi titulacion por usar ia","que pasa si altero evidencias con ia","que pasa si simulo actividades con inteligencia artificial","que sucede si uso informacion falsa","pueden rechazar mi reporte por usar ia","que pasa si comparto informacion confidencial en chatgpt","es falta academica usar mal la ia","la ia cuenta como plagio","que sanciones existen por usar ia","puedo tener problemas por usar inteligencia artificial","uso incorrecto de inteligencia artificial","que pasa si no puedo defender mi reporte","me pueden pedir correcciones por usar ia","puedo reprobar mi proyecto de estadia","consecuencias academicas del uso de ia","penalizaciones por usar chatgpt","que pasa si el reporte no es de mi autoria","que ocurre si la ia hizo gran parte de mi reporte","puedo recibir una sancion academica","riesgos de usar inteligencia artificial en estadias","que pasa si incumplo los lineamientos de ia"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Debo guardar evidencia del uso de inteligencia artificial durante mi estadía?','Sí. De acuerdo con los lineamientos institucionales, el estudiantado deberá conservar evidencia del uso de herramientas de inteligencia artificial durante la elaboración del Reporte Final de Estadía. Se recomienda guardar los prompts o instrucciones utilizadas, las respuestas generadas, capturas de pantalla y cualquier otro elemento que permita demostrar cómo fue utilizada la herramienta. Esta información podrá ser solicitada por la asesoría académica, la coordinación correspondiente o las instancias competentes para verificar el uso ético, responsable y adecuado de la inteligencia artificial. Si tienes dudas sobre qué evidencias conservar o cómo documentar el uso de estas herramientas, puedes comunicarte al correo practicas@uttt.edu.mx, al teléfono 773 732 9100 extensiones 209 o 108, o acudir con tu Dirección de Carrera para recibir orientación.','alumnos',true,'["debo guardar evidencia de ia","tengo que guardar evidencia de chatgpt","debo guardar los prompts","tengo que guardar los prompts","debo conservar los prompts","me pueden pedir los prompts","tengo que anexar los prompts","debo guardar capturas de chatgpt","tengo que guardar capturas","debo conservar capturas de pantalla","debo guardar las respuestas de chatgpt","tengo que guardar respuestas de ia","debo conservar conversaciones de ia","tengo que guardar conversaciones de chatgpt","me pueden pedir evidencia del uso de ia","como demuestro que use ia","como documento el uso de inteligencia artificial","debo registrar el uso de chatgpt","tengo que conservar historial de chatgpt","debo guardar el historial de ia","evidencia del uso de inteligencia artificial","que evidencias debo conservar","que documentos debo guardar sobre ia","como comprobar el uso de ia","como justificar el uso de chatgpt","debo anexar capturas de pantalla","debo guardar pruebas del uso de ia","me pueden solicitar capturas de chatgpt","debo guardar conversaciones de gemini","debo conservar respuestas de copilot","evidencia de herramientas de ia","como respaldar el uso de inteligencia artificial","que pasa si no guardo evidencia de ia","es obligatorio guardar evidencia de ia","debo guardar los chats utilizados","tengo que conservar mis consultas a ia","pueden revisar mis prompts","pueden pedirme las respuestas generadas","debo conservar el proceso de uso de ia","como demostrar que use inteligencia artificial correctamente","uso responsable de inteligencia artificial","evidencias de chatgpt para estadias","que debo guardar de la ia","historial de uso de inteligencia artificial","registro del uso de chatgpt","debo respaldar mis consultas de ia","conservar evidencia academica de ia","como acreditar el uso de herramientas de ia","documentacion del uso de inteligencia artificial","seguimiento del uso de ia en estadias"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Puedo compartir información de mi empresa en ChatGPT o en otras herramientas de inteligencia artificial?','No. De acuerdo con los lineamientos institucionales, está prohibido ingresar, cargar, copiar o compartir en herramientas públicas de inteligencia artificial información confidencial, datos personales, datos sensibles, información estratégica, documentos internos, procesos, bases de datos o cualquier información de la empresa receptora, de la Universidad o de terceros sin autorización expresa y sin cumplir la normativa aplicable. Antes de utilizar herramientas de inteligencia artificial con información relacionada con tu proyecto de estadía, se recomienda solicitar autorización a la empresa receptora y proteger la confidencialidad de la información. En caso de requerir ejemplos o contextos para trabajar con herramientas de IA, se recomienda utilizar información anonimizada, general o hipotética. Si tienes dudas sobre el uso adecuado de información institucional o empresarial, puedes comunicarte al correo practicas@uttt.edu.mx, al teléfono 773 732 9100 extensiones 209 o 108, o acudir con tu Dirección de Carrera para recibir orientación.','alumnos',true,'["puedo compartir informacion de mi empresa en chatgpt","puedo subir documentos de mi empresa a chatgpt","puedo usar informacion de la empresa en inteligencia artificial","puedo cargar archivos de la empresa en chatgpt","puedo compartir informacion confidencial con ia","puedo usar datos internos de la empresa en chatgpt","puedo subir reportes de la empresa a ia","puedo copiar informacion de la empresa en chatgpt","puedo usar documentos internos en inteligencia artificial","esta permitido compartir informacion empresarial con ia","puedo subir bases de datos a chatgpt","puedo compartir procesos internos de la empresa","puedo mostrar informacion de mi empresa a una ia","puedo cargar documentos confidenciales en gemini","puedo usar datos de mi proyecto en chatgpt","puedo subir archivos de mi estadia a ia","puedo compartir informacion institucional con inteligencia artificial","puedo compartir datos sensibles con ia","puedo subir informacion privada a chatgpt","que informacion puedo compartir con ia","que informacion no puedo compartir con chatgpt","confidencialidad en inteligencia artificial","puedo usar datos reales de la empresa en ia","puedo copiar informacion de la universidad en chatgpt","puedo compartir manuales internos en ia","puedo subir indicadores de la empresa a chatgpt","puedo usar informacion estrategica en inteligencia artificial","puedo compartir procesos confidenciales","puedo subir evidencias de la empresa a ia","puedo mostrar documentos empresariales a chatgpt","puedo utilizar informacion reservada en ia","que dice el reglamento sobre informacion confidencial","puedo compartir datos personales con chatgpt","puedo cargar expedientes en inteligencia artificial","puedo usar capturas internas de la empresa","puedo compartir bases de datos empresariales","puedo ingresar informacion privada en gemini","puedo usar informacion institucional en ia","puedo subir documentos de la universidad a chatgpt","puedo compartir informacion de terceros en inteligencia artificial","esta permitido compartir informacion sensible","proteccion de datos en chatgpt","uso de informacion confidencial en ia","puedo compartir informacion de clientes en chatgpt","puedo subir informacion empresarial a copilot","puedo compartir informacion de mi proyecto con ia","puedo usar datos reales en herramientas de inteligencia artificial","confidencialidad de la empresa en chatgpt","informacion protegida en inteligencia artificial","restricciones sobre informacion confidencial en ia"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Puedo usar información generada por inteligencia artificial sin verificarla?','No. De acuerdo con los lineamientos institucionales, toda información obtenida, sugerida, organizada o reformulada mediante herramientas de inteligencia artificial debe ser revisada, validada y contrastada con fuentes académicas, técnicas, normativas o documentales confiables antes de incorporarse al Reporte Final de Estadía. La inteligencia artificial puede cometer errores, generar información inexacta, incompleta o referencias inexistentes, por lo que el estudiantado es responsable de verificar la autenticidad, pertinencia y veracidad de toda la información utilizada. La inteligencia artificial no sustituye la consulta de libros, artículos científicos, normas técnicas, manuales institucionales o documentación especializada. Si tienes dudas sobre la validación de información o el uso correcto de fuentes en tu reporte de estadía, puedes comunicarte al correo practicas@uttt.edu.mx, al teléfono 773 732 9100 extensiones 209 o 108, o acudir con tu Dirección de Carrera para recibir orientación.','alumnos',true,'["puedo usar informacion de ia sin verificar","puedo usar informacion de chatgpt sin revisar","debo verificar la informacion de chatgpt","tengo que revisar la informacion de ia","puedo copiar informacion de chatgpt directamente","puedo pegar informacion de gemini en mi reporte","es obligatorio verificar la informacion de ia","debo validar lo que me responde chatgpt","puedo confiar totalmente en la inteligencia artificial","la informacion de ia siempre es correcta","debo comprobar la informacion de chatgpt","puedo usar respuestas de ia sin revisar","puedo usar informacion generada por inteligencia artificial","debo contrastar la informacion de ia","como verifico informacion generada por ia","puedo usar datos de chatgpt sin fuentes","debo buscar fuentes adicionales","chatgpt cuenta como fuente academica","la inteligencia artificial es una fuente confiable","puedo usar respuestas de gemini directamente","puedo usar informacion de copilot sin validar","debo revisar las referencias de ia","puedo utilizar contenido generado por ia","que pasa si uso informacion incorrecta de ia","debo corroborar la informacion generada","puedo usar definiciones de chatgpt","puedo usar explicaciones de inteligencia artificial","debo verificar datos obtenidos por ia","puedo utilizar informacion automatica en mi reporte","la universidad exige verificar informacion de ia","puedo confiar en referencias generadas por chatgpt","puedo usar bibliografia sugerida por ia","debo comprobar las fuentes recomendadas por ia","que tan confiable es la informacion de chatgpt","puedo usar resultados de inteligencia artificial","debo validar contenido generado automaticamente","la informacion de gemini necesita revision","puedo copiar informacion de deepseek","debo revisar las respuestas de claude","puedo basarme solo en inteligencia artificial","la ia reemplaza la investigacion academica","puedo usar informacion de internet generada por ia","como validar informacion obtenida de chatgpt","que dice el reglamento sobre verificar informacion","es obligatorio contrastar la informacion","debo consultar libros y articulos ademas de ia","puedo usar contenido de ia sin evidencia","debo confirmar que las fuentes existan","puedo usar informacion de ia como unica fuente","validacion de informacion generada por inteligencia artificial"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Pueden pedirme una defensa oral o explicación de mi reporte de estadía?','Sí. De acuerdo con los lineamientos institucionales, la asesoría académica, la asesoría de la unidad económica o las instancias correspondientes podrán solicitar una defensa oral, explicación técnica o exposición del trabajo desarrollado durante la estadía. Esta actividad tiene como finalidad verificar la autoría del reporte, la comprensión del proyecto realizado, la congruencia entre las actividades desarrolladas y los resultados obtenidos, así como el dominio técnico del tema por parte del estudiantado. Por ello, es importante que conozcas y comprendas plenamente el contenido de tu reporte, las actividades realizadas, la metodología empleada y los resultados alcanzados. Si tienes dudas sobre el proceso de evaluación de tu estadía, puedes comunicarte al correo practicas@uttt.edu.mx, al teléfono 773 732 9100 extensiones 209 o 108, o acudir con tu Dirección de Carrera para recibir orientación.','alumnos',true,'["tengo que defender mi reporte de estadia","hay defensa oral de estadia","debo exponer mi estadia","tengo que presentar mi proyecto de estadia","me pueden pedir una defensa oral","me pueden preguntar sobre mi reporte","debo explicar mi reporte de estadia","hay exposicion de estadias","tengo que hablar sobre mi proyecto","pueden entrevistarme sobre mi estadia","debo demostrar que hice mi proyecto","me pueden hacer preguntas de mi reporte","tengo que defender mi trabajo de estadia","pueden pedirme explicar mi metodologia","debo explicar mis resultados","hay examen de estadia","me pueden evaluar oralmente","tengo que hacer una presentacion de estadia","debo acreditar mi reporte oralmente","pueden cuestionarme sobre el proyecto","tengo que exponer frente a un jurado","me pueden pedir evidencias de mi proyecto","debo demostrar autoria de mi reporte","pueden verificar que yo hice el reporte","como es la defensa de estadia","que preguntan en la defensa de estadia","pueden preguntarme sobre mis actividades","tengo que explicar las conclusiones","debo justificar los resultados obtenidos","pueden revisar si entiendo mi reporte","me pueden pedir explicar el contenido","es obligatorio presentar mi proyecto","debo defender oralmente mi estadia","hay entrevista de estadia","pueden pedirme una explicacion tecnica","tengo que demostrar conocimientos del proyecto","puedo reprobar si no explico mi reporte","que pasa si no se explicar mi reporte","pueden pedirme una exposicion","debo conocer todo mi reporte","pueden preguntarme sobre la empresa","me pueden pedir aclaraciones del proyecto","pueden validar que hice las actividades","hay revision oral del reporte","debo explicar las evidencias presentadas","pueden solicitar una defensa academica","tengo que demostrar dominio del tema","pueden pedirme justificar mi metodologia","evaluacion oral de estadias","explicacion del reporte final de estadia"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La inteligencia artificial puede sustituir mi experiencia o trabajo realizado durante la estadía?','No. De acuerdo con los lineamientos institucionales, la inteligencia artificial debe utilizarse únicamente como una herramienta de apoyo complementaria y no puede sustituir la experiencia profesional, la autoría intelectual, el análisis crítico, las actividades desarrolladas, las decisiones académicas ni los resultados obtenidos durante la estadía. El Reporte Final de Estadía debe reflejar el trabajo real realizado por el estudiante en la unidad receptora, así como las competencias, conocimientos y habilidades adquiridas durante su formación. La inteligencia artificial puede apoyar en tareas auxiliares, pero la responsabilidad, comprensión, interpretación y defensa del proyecto corresponden exclusivamente al estudiantado. Si tienes dudas sobre los alcances permitidos del uso de inteligencia artificial durante tu estadía, puedes comunicarte al correo practicas@uttt.edu.mx, al teléfono 773 732 9100 extensiones 209 o 108, o acudir con tu Dirección de Carrera para recibir orientación.','alumnos',true,'["la inteligencia artificial puede sustituir mi experiencia","chatgpt puede hacer mi estadia","la ia puede hacer mi proyecto","puedo dejar que chatgpt haga todo","la inteligencia artificial puede reemplazarme","puedo hacer toda mi estadia con ia","la ia puede hacer mi reporte completo","chatgpt puede sustituir mi trabajo","puedo usar solo inteligencia artificial","la ia reemplaza la experiencia profesional","puedo hacer la estadia sin trabajar en la empresa","chatgpt puede hacer mi proyecto final","la ia puede sustituir las actividades realizadas","puedo dejar que gemini haga mi reporte","copilot puede hacer toda mi estadia","deepseek puede hacer mi proyecto","claude puede redactar toda mi experiencia","puedo entregar un reporte hecho por ia","la inteligencia artificial puede hacer mis conclusiones","la ia puede reemplazar mi analisis","chatgpt puede sustituir mi investigacion","puedo usar inteligencia artificial para todo","la ia puede hacer mis actividades","puedo depender totalmente de chatgpt","la universidad permite que la ia haga el reporte","la ia puede reemplazar el trabajo real","puedo presentar contenido generado automaticamente","la inteligencia artificial puede hacer mi metodologia","la ia puede sustituir mi aprendizaje","puedo usar solo chatgpt para graduarme","chatgpt puede hacer mi trabajo de estadia","la ia puede reemplazar mis resultados","puedo dejar que una ia haga mi proyecto","la inteligencia artificial sustituye al estudiante","puedo usar ia sin hacer actividades reales","la ia puede hacer la experiencia profesional","puedo generar todo mi reporte con chatgpt","la inteligencia artificial puede hacer mi defensa","la ia puede reemplazar la autoria","puedo usar solo gemini para mi reporte","puedo dejar que copilot haga todo el trabajo","la ia puede sustituir mis competencias","chatgpt puede reemplazar mi trabajo en la empresa","puedo usar inteligencia artificial en lugar de trabajar","la experiencia real puede ser sustituida por ia","puedo presentar un proyecto generado por ia","la inteligencia artificial reemplaza al estudiante","la ia puede hacer todo por mi","puedo graduarme con un reporte hecho por chatgpt","alcances de la inteligencia artificial en estadias"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Puedo utilizar referencias bibliográficas generadas por inteligencia artificial en mi reporte de estadía?','Sí, pero únicamente después de verificarlas. Las herramientas de inteligencia artificial pueden utilizarse como apoyo para generar referencias bibliográficas o dar formato conforme a normas APA; sin embargo, el estudiantado tiene la obligación de comprobar que cada fuente exista, sea real, pertinente y haya sido efectivamente consultada. Está prohibido incluir referencias ficticias, inexistentes, incorrectas o no verificadas generadas por herramientas de inteligencia artificial. La responsabilidad sobre la autenticidad y validez de las fuentes utilizadas recae en el estudiante. Si tienes dudas sobre el uso correcto de referencias bibliográficas o normas APA en tu Reporte Final de Estadía, puedes comunicarte al correo practicas@uttt.edu.mx, al teléfono 773 732 9100 extensiones 209 o 108, o acudir con tu Dirección de Carrera para recibir orientación.','alumnos',true,'["puedo usar referencias de chatgpt","puedo usar bibliografia de chatgpt","las referencias de ia son validas","puedo copiar referencias de gemini","puedo usar fuentes generadas por inteligencia artificial","debo verificar las referencias de ia","chatgpt me dio una referencia","puedo usar bibliografia generada por ia","las fuentes de chatgpt son confiables","puedo citar referencias generadas por ia","debo comprobar las referencias de chatgpt","puedo usar referencias de copilot","puedo usar bibliografia de gemini","puedo usar referencias sugeridas por inteligencia artificial","chatgpt genera referencias reales","puedo incluir referencias de ia en mi reporte","debo verificar que las fuentes existan","puedo usar citas de inteligencia artificial","puedo usar bibliografia sin verificar","las referencias generadas por ia son oficiales","chatgpt puede hacer mis referencias","puedo confiar en referencias de ia","debo revisar las fuentes recomendadas","puedo usar referencias de deepseek","puedo usar referencias de claude","como verificar referencias de chatgpt","puedo utilizar bibliografia automatica","puedo copiar citas de inteligencia artificial","la ia puede generar referencias apa","puedo usar fuentes sugeridas por chatgpt","debo comprobar bibliografia generada por ia","puedo citar articulos sugeridos por ia","chatgpt inventa referencias","puedo usar referencias sin consultarlas","es obligatorio verificar las fuentes","puedo utilizar bibliografia no verificada","referencias falsas generadas por ia","puedo incluir fuentes inexistentes","como validar referencias bibliograficas","que pasa si uso referencias falsas","puedo usar referencias academicas de chatgpt","puedo copiar bibliografia generada automaticamente","la inteligencia artificial genera fuentes reales","puedo usar bibliografia de internet generada por ia","puedo citar fuentes recomendadas por gemini","las referencias de copilot son validas","puedo usar normas apa generadas por ia","uso correcto de referencias generadas por inteligencia artificial","verificacion de fuentes bibliograficas","referencias bibliograficas en estadias"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debe contener mi Reporte Final de Estadía?','De acuerdo con la Guía para el Reporte Final de Estadía de la Universidad Tecnológica de Tula-Tepeji, el reporte debe contener los siguientes apartados: Portada, Resumen, Palabras clave, Abstract, Keywords, Agradecimientos (opcional), Introducción, Descripción de la unidad económica, Contexto y planteamiento del problema, Objetivo general, Objetivos específicos, Alternativas de solución, Descripción de la propuesta de solución, Hipótesis (cuando aplique), Justificación, Marco teórico, Metodología, Desarrollo del proyecto, Resultados, Recomendaciones y/o sugerencias, Conclusiones, Declaratoria de autenticidad (cuando aplique), Declaración de uso de herramientas de Inteligencia Artificial, Referencias y Anexos. Se recomienda consultar la guía oficial y los formatos actualizados en https://uttt.edu.mx/ServiciosDeVinculacion/Alumnos/Es.Estadia.html. Si tienes dudas sobre la estructura o contenido de tu reporte, puedes solicitar orientación a tu asesor académico, a tu Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["que debe contener mi reporte de estadia","contenido del reporte de estadia","estructura del reporte de estadia","como se integra el reporte de estadia","que apartados lleva el reporte de estadia","que incluye el reporte final de estadia","como hacer mi reporte de estadia","guia para reporte de estadia","elementos del reporte de estadia","partes del reporte de estadia","como esta conformado el reporte final","que lleva un reporte de estadia","como elaborar el reporte final de estadia","que necesito para mi reporte de estadia","apartados obligatorios del reporte","estructura del reporte final","que capitulos lleva el reporte","contenido obligatorio del reporte","como hacer el reporte final","que secciones tiene el reporte","que informacion lleva el reporte","formato del reporte de estadia","como organizar mi reporte de estadia","orden del reporte de estadia","requisitos del reporte final","que debe llevar mi proyecto de estadia","como presentar el reporte de estadia","componentes del reporte final","que incluye la guia de estadia","como estructurar el reporte","que contiene la guia de reporte","que documentos integran el reporte","que elementos debe tener el reporte","que lleva el informe de estadia","como redactar el reporte final","contenido de mi proyecto final","que se necesita para entregar el reporte","que debe contener el documento final","como esta organizado el reporte","que apartados son obligatorios","que debe incluir mi estadia","estructura oficial del reporte","como hacer un reporte final de estadia","que partes tiene el informe final","guia oficial de reporte de estadia","como desarrollar el reporte","contenido del informe final de estadia","que debo entregar en el reporte final","reporte final de estadia requisitos","que debe llevar mi reporte final de estadia"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Dónde puedo consultar la guía oficial para elaborar mi Reporte Final de Estadía?','Puedes solicitar la Guía para el Reporte Final de Estadía directamente con tu asesor académico o en tu Dirección de Carrera, quienes podrán orientarte sobre la estructura, requisitos y lineamientos vigentes para la elaboración del documento. También puedes consultar la guía digital en el siguiente enlace: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. Se recomienda revisar la guía completa antes de comenzar la redacción de tu reporte, ya que contiene especificaciones sobre formato, contenido, apartados obligatorios, referencias, anexos y lineamientos relacionados con el uso de inteligencia artificial. Si necesitas apoyo adicional, puedes comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["donde puedo consultar la guia de estadia","donde consigo la guia de estadia","donde encuentro la guia del reporte de estadia","como obtengo la guia de estadia","donde descargo la guia de estadia","guia oficial de estadia","manual de reporte de estadia","donde esta la guia del reporte final","como consultar la guia de reporte","existe una guia para estadias","donde estan los lineamientos del reporte","donde veo la estructura del reporte","guia para elaborar reporte de estadia","como saber que lleva el reporte","donde encuentro los requisitos del reporte","donde consultar el reporte de estadia","como conseguir la guia oficial","quien me puede dar la guia de estadia","asesor academico guia de estadia","direccion de carrera guia de estadia","donde pido la guia del reporte","donde veo los formatos de estadia","guia para reporte final","reporte final de estadia guia","documento de guia de estadias","lineamientos del reporte final","como elaborar mi reporte de estadia","donde consultar la guia oficial","donde ver el formato del reporte","quien me orienta para el reporte","como obtener los lineamientos de estadia","donde esta el manual de estadia","guia de estadias uttt","documentacion para reporte final","como hacer mi reporte final","donde encuentro informacion del reporte","guia institucional de estadias","donde revisar los apartados del reporte","formato oficial del reporte","estructura oficial de estadia","como saber los requisitos del reporte final","donde consultar el documento de estadia","guia para alumnos de estadia","manual oficial de reporte final","como descargar la guia de estadia","documento oficial para estadias","orientacion para reporte final","lineamientos de elaboracion del reporte","guia digital de estadia","informacion para elaborar mi reporte"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');   
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué formato debe tener mi Reporte Final de Estadía?','El Reporte Final de Estadía debe elaborarse conforme a la Guía Oficial para el Reporte Final de Estadía de la Universidad Tecnológica de Tula-Tepeji. Entre los principales requisitos se encuentran el uso de hoja tamaño carta, márgenes de 2.5 cm, tipografía Arial tamaño 12, interlineado de 1.5, numeración de páginas, citas y referencias conforme a normas APA vigentes y entrega en formato PDF. Para conocer todas las especificaciones y requisitos actualizados, puedes solicitar la guía con tu asesor académico, en tu Dirección de Carrera o consultarla en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. Si tienes dudas, puedes comunicarte al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["que formato debe tener mi reporte de estadia","formato del reporte de estadia","como debe ir el reporte de estadia","requisitos de formato del reporte","especificaciones del reporte de estadia","como presentar el reporte final","formato oficial del reporte","como debe estar elaborado el reporte","estructura y formato del reporte","requisitos del reporte final","como entregar mi reporte de estadia","lineamientos del formato del reporte","como debe verse el reporte","caracteristicas del reporte final","guia de formato de estadia","formato institucional del reporte","como hacer el formato del reporte","que formato lleva el reporte","especificaciones tecnicas del reporte","requisitos de presentacion del reporte"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué tipo de letra debe llevar mi Reporte Final de Estadía?','De acuerdo con la Guía para el Reporte Final de Estadía, la tipografía general del documento debe ser Arial tamaño 12 puntos. Se recomienda mantener el mismo tipo y tamaño de letra en todo el documento para conservar uniformidad y presentación profesional. Si tienes dudas, consulta a tu asesor académico o la guía oficial de estadías.','alumnos',true,'["que letra lleva el reporte","tipo de letra del reporte","que fuente lleva el reporte","que tipografia debo usar","letra para reporte de estadia","arial o times new roman","tamaño de letra del reporte","fuente del reporte final","que letra pide la universidad","tipo de fuente del reporte","como debe ser la letra del reporte","arial 12 reporte","formato de letra estadia","que letra uso en el reporte","tipografia oficial del reporte","tipo de letra estadias","letra para reporte final","fuente oficial del reporte","caracteristicas de letra del reporte","que tamaño de fuente lleva el reporte"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué márgenes debe tener mi Reporte Final de Estadía?','La guía institucional establece que el Reporte Final de Estadía debe utilizar márgenes de 2.5 centímetros en todos los lados de la hoja: superior, inferior, izquierdo y derecho. Esto ayuda a mantener una presentación uniforme y profesional del documento.','alumnos',true,'["que margenes lleva el reporte","margenes del reporte de estadia","cuanto deben medir los margenes","margen izquierdo reporte","margen derecho reporte","margen superior reporte","margen inferior reporte","formato de margenes","que medidas llevan los margenes","como configurar margenes en word","margenes para estadia","tamaño de margenes","configuracion de margenes","margenes oficiales del reporte","cuantos centimetros de margen","formato de pagina reporte","medidas de margenes","margenes documento estadia","como van los margenes","requisitos de margenes"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué interlineado debe llevar mi Reporte Final de Estadía?','El Reporte Final de Estadía debe elaborarse utilizando interlineado de 1.5 en todo el documento, conforme a la guía institucional vigente. Esto permite mejorar la legibilidad y mantener uniformidad en la presentación del trabajo.','alumnos',true,'["que interlineado lleva el reporte","interlineado del reporte de estadia","espaciado del reporte","interlineado 1.5","como debe ir el interlineado","espacio entre lineas del reporte","interlineado oficial","interlineado para estadia","configuracion de interlineado","espaciado de lineas","interlineado word reporte","formato de interlineado","reporte con interlineado 1.5","como configurar interlineado","interlineado institucional","espaciado del documento","interlineado del informe","lineas del reporte","separacion entre lineas","requisitos de interlineado"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo debe ir la numeración de páginas en mi Reporte Final de Estadía?','La numeración debe colocarse en la esquina inferior derecha de cada página utilizando la función automática de numeración del procesador de texto. La portada también debe contabilizarse y aparecer como página 1.','alumnos',true,'["numeracion de paginas reporte","como numerar el reporte","donde va el numero de pagina","la portada cuenta como pagina","como poner numero de pagina","numeracion del reporte final","ubicacion de numeracion","numero de pagina inferior derecha","paginas del reporte","formato de numeracion","numeracion oficial del reporte","como contar las paginas","portada pagina 1","donde va la numeracion","configurar numeracion","numero de pagina estadia","como numerar estadias","numeracion institucional","formato de paginas","requisitos de numeracion"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué formato de citas y referencias debo utilizar en mi Reporte Final de Estadía?','Todas las fuentes de información utilizadas en el Reporte Final de Estadía deben citarse y referenciarse conforme a las Normas APA vigentes. Es importante reconocer adecuadamente las ideas, datos y textos de otros autores para evitar el plagio y mantener la integridad académica del trabajo.','alumnos',true,'["que formato apa debo usar","citas apa en estadia","referencias apa","como citar en el reporte","formato de citas","normas apa reporte","como hacer referencias apa","que version de apa usar","como referenciar fuentes","citas bibliograficas reporte","referencias bibliograficas","formato apa vigente","como citar libros","como citar paginas web","como hacer bibliografia","normas apa estadia","citas y referencias","formato academico de citas","evitar plagio en reporte","como citar correctamente"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cuántas páginas debe tener mi Reporte Final de Estadía?','De acuerdo con la guía institucional, el Reporte Final de Estadía debe tener una extensión promedio de 60 páginas sin considerar los anexos. La cantidad final puede variar dependiendo de la complejidad del proyecto y de la información necesaria para documentar adecuadamente el trabajo realizado.','alumnos',true,'["cuantas paginas debe tener el reporte","cuantas hojas lleva el reporte","extension del reporte de estadia","cuanto debe medir el reporte","numero de paginas del reporte","reporte de 60 paginas","cuantas cuartillas lleva","longitud del reporte","tamaño del reporte final","cuantas hojas son necesarias","minimo de paginas reporte","maximo de paginas reporte","promedio de paginas","extension del informe","cantidad de paginas estadia","cuantas paginas pide la universidad","reporte final extension","numero de hojas","cuantas paginas son","requisitos de extension"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Debo entregar mi Reporte Final de Estadía en PDF?','Sí. La guía institucional establece que el Reporte Final de Estadía debe entregarse en formato digital PDF, respetando la estructura, contenido y especificaciones establecidas por la Universidad. Antes de realizar la entrega, verifica con tu asesor académico cualquier requisito adicional de tu programa educativo.','alumnos',true,'["debo entregar el reporte en pdf","el reporte va en pdf","puedo entregar el reporte en word","formato de entrega del reporte","como entregar el reporte final","reporte digital pdf","entrega de estadia pdf","se entrega impreso o digital","archivo pdf estadia","formato final del reporte","como enviar el reporte","entrega digital del reporte","reporte en word o pdf","documento pdf estadia","como subir el reporte","archivo final de estadia","requisitos de entrega","entrega electronica del reporte","pdf obligatorio","formato de archivo del reporte"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');   
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debe contener la portada de mi Reporte Final de Estadía?','La portada de tu Reporte Final de Estadía debe contener los elementos establecidos en la guía institucional, tales como el nombre de la Universidad Tecnológica de Tula-Tepeji, nombre del programa educativo, título del proyecto, nombre de la unidad económica, nombre del estudiante, nombre del asesor académico, nombre del asesor de la unidad económica, lugar y fecha de elaboración. Se recomienda seguir el formato oficial indicado en la guía. Para conocer el formato completo de la portada, puedes consultar la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. También puedes solicitar orientación a tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["portada reporte de estadia","que lleva la portada","como hacer la portada","que contiene la portada","portada de estadias","formato de portada","ejemplo de portada","datos de la portada","como debe ir la portada","requisitos de portada","portada oficial","portada reporte final","que poner en la portada","estructura de portada","como elaborar la portada","elementos de la portada","titulo de la portada","datos del asesor en portada","portada institucional","portada de mi proyecto"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debe contener el resumen de mi Reporte Final de Estadía?','El resumen debe presentar de forma breve y clara el proyecto realizado durante la estadía. Generalmente incluye los antecedentes, la problemática abordada, el objetivo principal, la metodología utilizada, los resultados obtenidos y una conclusión general. Su finalidad es permitir al lector comprender rápidamente el contenido del proyecto. Para conocer las especificaciones completas del resumen, consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. También puedes solicitar apoyo a tu asesor académico, Dirección de Carrera o al Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["que debe contener el resumen","como hacer el resumen","resumen del reporte","que lleva el resumen","como redactar el resumen","resumen de estadia","ejemplo de resumen","estructura del resumen","contenido del resumen","resumen proyecto estadia","como elaborar el resumen","partes del resumen","requisitos del resumen","que poner en el resumen","cuantas palabras lleva el resumen","resumen ejecutivo estadia","introduccion resumida","resumen del proyecto","como iniciar el resumen","que informacion lleva el resumen"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué son las palabras clave de mi Reporte Final de Estadía?','Las palabras clave son términos que representan los conceptos más importantes de tu proyecto y ayudan a identificar rápidamente los temas principales abordados en el reporte. Generalmente se incluyen después del resumen y deben estar relacionadas directamente con el contenido del proyecto. Para conocer más detalles sobre este apartado, consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. Si tienes dudas, puedes solicitar orientación a tu asesor académico o Dirección de Carrera.','alumnos',true,'["que son las palabras clave","palabras clave reporte","keywords en español","como hacer palabras clave","cuantas palabras clave","ejemplos de palabras clave","que poner en palabras clave","palabras clave estadia","como elegir palabras clave","contenido de palabras clave","palabras importantes del proyecto","palabras clave del reporte","requisitos palabras clave","como redactar palabras clave","terminos clave del proyecto","que significan palabras clave","palabras clave de investigacion","identificar palabras clave","que palabras usar","palabras clave ejemplo"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debe contener el abstract de mi Reporte Final de Estadía?','El abstract es la versión en inglés del resumen de tu Reporte Final de Estadía. Debe contener la misma información presentada en el resumen en español, incluyendo antecedentes, objetivo, metodología, resultados y conclusión, pero redactada correctamente en idioma inglés. Para conocer las recomendaciones y estructura completa, consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. También puedes solicitar apoyo a tu asesor académico o Dirección de Carrera.','alumnos',true,'["que es el abstract","como hacer el abstract","abstract del reporte","resumen en ingles","que lleva el abstract","como redactar el abstract","abstract de estadia","ejemplo de abstract","contenido del abstract","estructura del abstract","traduccion del resumen","abstract proyecto estadia","como elaborar el abstract","requisitos del abstract","abstract reporte final","que poner en el abstract","informacion del abstract","como escribir el abstract","abstract en ingles","parte abstract del reporte"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué son las keywords de mi Reporte Final de Estadía?','Las keywords son la traducción al idioma inglés de las palabras clave de tu proyecto. Deben representar los conceptos principales abordados en el Reporte Final de Estadía y estar relacionadas con el contenido del abstract. Para conocer más detalles sobre este apartado, consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. Si tienes dudas, puedes solicitar apoyo a tu asesor académico, Dirección de Carrera o al Departamento de Estadías e Inserción Laboral.','alumnos',true,'["que son las keywords","keywords reporte","palabras clave en ingles","como hacer keywords","keywords de estadia","que poner en keywords","ejemplos de keywords","cuantas keywords lleva","keywords del proyecto","como redactar keywords","keywords abstract","terminos clave en ingles","keywords reporte final","traduccion de palabras clave","contenido de keywords","requisitos de keywords","como elegir keywords","keywords investigacion","keywords ejemplo","parte de keywords"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');   
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debe contener la introducción de mi Reporte Final de Estadía?','La introducción debe presentar una visión general del proyecto realizado durante la estadía. Debe incluir antecedentes del tema, contexto general, importancia del proyecto, objetivo principal y una breve descripción de los apartados que integran el reporte. Su finalidad es proporcionar al lector una comprensión inicial del trabajo desarrollado. Para conocer las especificaciones completas, consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. También puedes solicitar orientación a tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["que debe contener la introduccion","como hacer la introduccion","introduccion del reporte","que lleva la introduccion","como redactar la introduccion","introduccion de estadia","ejemplo de introduccion","estructura de la introduccion","contenido de la introduccion","introduccion proyecto estadia","como elaborar la introduccion","partes de la introduccion","requisitos de la introduccion","que poner en la introduccion","introduccion reporte final","como iniciar la introduccion","introduccion del proyecto","informacion de la introduccion","introduccion ejemplo","que informacion lleva la introduccion"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debe incluir la descripción de la unidad económica en mi Reporte Final de Estadía?','La descripción de la unidad económica debe proporcionar información general de la empresa u organización donde realizaste tu estadía. Puede incluir antecedentes, giro, misión, visión, organigrama, productos o servicios ofrecidos, ubicación y el área específica donde desarrollaste tu proyecto. Este apartado permite contextualizar el entorno donde se llevó a cabo la estadía. Para más información consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing o solicita apoyo a tu asesor académico.','alumnos',true,'["descripcion de la unidad economica","que debe llevar la descripcion de la empresa","como describir la empresa","descripcion de la organizacion","que poner en la descripcion de la empresa","empresa en reporte de estadia","informacion de la empresa","como hacer la descripcion de la empresa","que incluir de la empresa","datos de la unidad economica","antecedentes de la empresa","mision y vision empresa","organigrama empresa","descripcion organizacional","descripcion institucional","area donde realice mi estadia","contexto de la empresa","como presentar la empresa","descripcion del lugar de estadia","informacion de la unidad receptora"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debe contener el contexto y planteamiento del problema de mi Reporte Final de Estadía?','El contexto y planteamiento del problema debe describir de manera clara la situación que originó el proyecto. Se recomienda explicar el entorno donde se presenta la problemática, sus causas, consecuencias e impacto dentro de la unidad económica. Este apartado debe enfocarse en describir el problema y justificar la necesidad de resolverlo, evitando presentar soluciones anticipadamente. Para conocer más detalles consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing.','alumnos',true,'["planteamiento del problema","que debe contener el planteamiento del problema","como hacer el planteamiento del problema","contexto del problema","como redactar el problema","problematica del proyecto","que poner en el planteamiento","planteamiento de estadia","ejemplo de planteamiento","descripcion del problema","como identificar el problema","problema del proyecto","contexto y planteamiento","causas del problema","impacto del problema","redaccion del problema","problema organizacional","problema de investigacion","situacion actual del problema","como elaborar el planteamiento"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo redactar el objetivo general de mi proyecto de estadía?','El objetivo general debe expresar claramente el propósito principal del proyecto y el resultado que se pretende alcanzar. Generalmente se redacta iniciando con un verbo en infinitivo como diseñar, implementar, desarrollar, optimizar, mejorar o evaluar. Debe responder qué se hará, para qué se hará y, de ser posible, dónde se aplicará. Para conocer ejemplos y lineamientos específicos consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing o solicita apoyo a tu asesor académico.','alumnos',true,'["objetivo general","como hacer el objetivo general","como redactar el objetivo general","que debe contener el objetivo general","objetivo principal del proyecto","ejemplo de objetivo general","objetivo general de estadia","como escribir el objetivo general","verbo en infinitivo objetivo","objetivo del proyecto","como elaborar el objetivo general","redaccion del objetivo general","objetivo general ejemplo","objetivo principal","como definir el objetivo","que poner en el objetivo general","objetivo general reporte","objetivo general del proyecto","como plantear el objetivo","estructura del objetivo general"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo redactar los objetivos específicos de mi proyecto de estadía?','Los objetivos específicos son las acciones concretas que permitirán alcanzar el objetivo general. Deben redactarse utilizando verbos en infinitivo y describir actividades medibles y alcanzables. Cada objetivo específico debe contribuir directamente al cumplimiento del objetivo general del proyecto. Para conocer ejemplos y recomendaciones, consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. También puedes solicitar orientación a tu asesor académico o Dirección de Carrera.','alumnos',true,'["objetivos especificos","como hacer objetivos especificos","como redactar objetivos especificos","que son los objetivos especificos","objetivos especificos de estadia","ejemplo de objetivos especificos","como elaborar objetivos especificos","objetivos secundarios","objetivos del proyecto","redaccion de objetivos especificos","verbos para objetivos especificos","estructura de objetivos especificos","objetivos medibles","como definir objetivos especificos","objetivos del reporte","que poner en los objetivos especificos","objetivos particulares","objetivos del trabajo","como plantear objetivos especificos","requisitos de objetivos especificos"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué son las alternativas de solución en mi proyecto de estadía?','Las alternativas de solución son las diferentes opciones o estrategias que pueden emplearse para resolver la problemática identificada en la unidad económica. En este apartado se deben presentar y comparar las posibles soluciones, analizando aspectos como viabilidad, recursos necesarios, tiempo de implementación, costos y beneficios. Esto permite justificar posteriormente la propuesta seleccionada. Para conocer más detalles consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. También puedes solicitar orientación a tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["alternativas de solucion","que son las alternativas de solucion","como hacer alternativas de solucion","alternativas para resolver el problema","opciones de solucion","soluciones del proyecto","como redactar alternativas de solucion","ejemplo de alternativas de solucion","alternativas de mejora","analisis de alternativas","propuestas de solucion","opciones para resolver la problematica","alternativas del proyecto","como comparar alternativas","seleccion de alternativas","soluciones posibles","alternativas de estadia","como presentar alternativas","alternativas de trabajo","alternativas de proyecto"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debe contener la propuesta de solución de mi proyecto de estadía?','La propuesta de solución debe describir la alternativa seleccionada para resolver la problemática identificada. Debe explicar en qué consiste la solución, por qué fue elegida, cuáles son sus beneficios esperados y cómo contribuirá a mejorar la situación detectada en la unidad económica. Este apartado debe estar sustentado con información técnica y argumentos que justifiquen su implementación. Para más información consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing o solicita apoyo a tu asesor académico.','alumnos',true,'["propuesta de solucion","que debe contener la propuesta de solucion","como hacer la propuesta de solucion","solucion seleccionada","propuesta del proyecto","como redactar la propuesta","descripcion de la solucion","propuesta de mejora","ejemplo de propuesta de solucion","solucion del problema","como presentar la propuesta","justificacion de la solucion","propuesta de estadia","contenido de la propuesta","propuesta tecnica","propuesta final","solucion propuesta","como elaborar la propuesta","que poner en la propuesta","propuesta de proyecto"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué es la hipótesis y cuándo debo incluirla en mi Reporte Final de Estadía?','La hipótesis es una posible respuesta o explicación provisional al problema planteado y sirve como base para orientar el desarrollo del proyecto. Este apartado suele utilizarse principalmente en proyectos con enfoque de investigación y deberá comprobarse o rechazarse con base en los resultados obtenidos. No todos los proyectos requieren una hipótesis, por lo que se recomienda validar este apartado con tu asesor académico. Para más información consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing.','alumnos',true,'["que es la hipotesis","hipotesis del proyecto","como hacer una hipotesis","cuando usar hipotesis","ejemplo de hipotesis","hipotesis de estadia","como redactar la hipotesis","que debe contener la hipotesis","hipotesis de investigacion","como elaborar una hipotesis","para que sirve la hipotesis","propuesta de hipotesis","hipotesis ejemplo","hipotesis del reporte","como plantear una hipotesis","que poner en la hipotesis","hipotesis academica","estructura de hipotesis","hipotesis del proyecto final","requisitos de hipotesis"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debe contener la justificación de mi proyecto de estadía?','La justificación explica la importancia del proyecto y las razones por las cuales debe realizarse. Debe describir los beneficios que aportará a la unidad económica, las personas beneficiadas, el impacto esperado y la relevancia de la solución propuesta. También puede incluir beneficios técnicos, económicos, sociales, ambientales o académicos derivados del proyecto. Para conocer más detalles consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. También puedes solicitar orientación a tu asesor académico o Dirección de Carrera.','alumnos',true,'["justificacion del proyecto","que debe contener la justificacion","como hacer la justificacion","como redactar la justificacion","justificacion de estadia","ejemplo de justificacion","importancia del proyecto","beneficios del proyecto","como elaborar la justificacion","justificacion ejemplo","que poner en la justificacion","justificacion academica","justificacion tecnica","impacto del proyecto","razones del proyecto","justificacion de investigacion","como argumentar la justificacion","contenido de la justificacion","estructura de la justificacion","justificacion del reporte"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo se compone el marco teórico de mi proyecto de estadía?','El marco teórico debe reunir los fundamentos conceptuales, técnicos, metodológicos, normativos o científicos que respaldan el desarrollo del proyecto. Generalmente incluye antecedentes del tema, teorías relacionadas, conceptos relevantes, normatividad aplicable y la información necesaria para comprender la problemática y la propuesta de solución. Se recomienda desarrollar este apartado de lo general a lo particular utilizando fuentes confiables y actualizadas. Para conocer la estructura completa consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. También puedes solicitar apoyo a tu asesor académico o Dirección de Carrera.','alumnos',true,'["marco teorico","como se compone el marco teorico","que debe contener el marco teorico","como hacer el marco teorico","marco teorico de estadia","ejemplo de marco teorico","como redactar el marco teorico","estructura del marco teorico","antecedentes del marco teorico","contenido del marco teorico","bases teoricas","conceptos del marco teorico","fundamentos teoricos","como elaborar el marco teorico","marco teorico del proyecto","informacion para el marco teorico","fuentes para marco teorico","teoria del proyecto","que poner en el marco teorico","marco teorico ejemplo"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debe contener la metodología de mi proyecto de estadía?','La metodología describe la forma en que se desarrolló el proyecto para alcanzar los objetivos planteados. Debe incluir las etapas realizadas, procedimientos aplicados, técnicas utilizadas, herramientas empleadas, recursos utilizados y, cuando sea pertinente, diagramas o representaciones gráficas que faciliten la comprensión del proceso seguido. Este apartado permite explicar de manera ordenada cómo se ejecutó el proyecto. Para conocer la estructura completa consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. También puedes solicitar orientación a tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["metodologia","que debe contener la metodologia","como hacer la metodologia","metodologia del proyecto","metodologia de estadia","como redactar la metodologia","ejemplo de metodologia","estructura de la metodologia","que poner en la metodologia","metodos utilizados","procedimiento del proyecto","como elaborar la metodologia","contenido de la metodologia","metodologia ejemplo","tecnicas utilizadas","herramientas utilizadas","etapas del proyecto","metodologia del reporte","como describir la metodologia","requisitos de metodologia"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debe incluir el desarrollo del proyecto en mi Reporte Final de Estadía?','El desarrollo del proyecto debe describir detalladamente las actividades realizadas durante la estadía, explicando el trabajo efectuado, las acciones implementadas, las herramientas utilizadas, las evidencias obtenidas y la aplicación de los conocimientos adquiridos durante la formación académica. Este apartado suele representar la parte central del reporte y permite mostrar cómo se ejecutó la propuesta de solución. Para conocer más detalles consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. También puedes solicitar apoyo a tu asesor académico o Dirección de Carrera.','alumnos',true,'["desarrollo del proyecto","que debe contener el desarrollo del proyecto","como hacer el desarrollo del proyecto","desarrollo de estadia","que poner en el desarrollo","actividades realizadas","ejemplo de desarrollo del proyecto","como redactar el desarrollo","contenido del desarrollo","estructura del desarrollo","desarrollo del reporte","trabajo realizado en estadia","como elaborar el desarrollo","evidencias del proyecto","actividades del proyecto","desarrollo proyecto final","desarrollo de actividades","como documentar el proyecto","desarrollo del trabajo","requisitos del desarrollo"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debe contener el apartado de resultados de mi proyecto de estadía?','El apartado de resultados debe presentar de manera clara los logros obtenidos durante la ejecución del proyecto. Puede incluir indicadores, comparativas, gráficas, tablas, evidencias, mediciones, mejoras alcanzadas o cualquier información que permita demostrar el impacto de la solución implementada. Los resultados deben estar relacionados con los objetivos planteados al inicio del proyecto. Para más información consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing o solicita orientación a tu asesor académico.','alumnos',true,'["resultados del proyecto","que debe contener resultados","como hacer los resultados","resultados de estadia","que poner en resultados","ejemplo de resultados","como redactar resultados","apartado de resultados","resultados obtenidos","evidencias de resultados","graficas en resultados","tablas de resultados","indicadores del proyecto","impacto del proyecto","resultado final","contenido de resultados","estructura de resultados","como presentar resultados","logros obtenidos","requisitos de resultados"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué son las recomendaciones y sugerencias en mi Reporte Final de Estadía?','Las recomendaciones y sugerencias son propuestas orientadas a mejorar, fortalecer o dar continuidad al proyecto realizado. En este apartado pueden incluirse acciones futuras, mejoras detectadas, oportunidades de crecimiento o estrategias que permitan mantener los beneficios obtenidos. Estas observaciones deben estar fundamentadas en los resultados y la experiencia adquirida durante la estadía. Para más detalles consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. También puedes solicitar apoyo a tu asesor académico o Dirección de Carrera.','alumnos',true,'["recomendaciones y sugerencias","que son las recomendaciones","como hacer recomendaciones","sugerencias del proyecto","recomendaciones de estadia","que poner en recomendaciones","ejemplo de recomendaciones","como redactar sugerencias","recomendaciones del reporte","mejoras del proyecto","acciones futuras","continuidad del proyecto","oportunidades de mejora","como elaborar recomendaciones","contenido de recomendaciones","sugerencias ejemplo","recomendaciones finales","propuestas de mejora","recomendaciones del trabajo","requisitos de recomendaciones"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debe contener la conclusión de mi Reporte Final de Estadía?','La conclusión debe presentar una reflexión final sobre el proyecto realizado, indicando si se cumplió el objetivo general, los objetivos específicos y los resultados esperados. También puede incluir los beneficios obtenidos, las principales aportaciones del proyecto y los aprendizajes adquiridos durante la estadía. Este apartado debe sintetizar los aspectos más importantes del trabajo realizado. Para conocer más detalles consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. También puedes solicitar orientación a tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["conclusion del proyecto","que debe contener la conclusion","como hacer la conclusion","conclusion de estadia","que poner en la conclusion","ejemplo de conclusion","como redactar la conclusion","conclusiones del reporte","cumplimiento de objetivos","resultado final del proyecto","reflexion final","como elaborar la conclusion","contenido de la conclusion","estructura de la conclusion","conclusion ejemplo","aprendizajes obtenidos","aportaciones del proyecto","conclusion del trabajo","requisitos de conclusion","conclusion reporte final"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');   
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué es la declaratoria de autenticidad en mi Reporte Final de Estadía?','La declaratoria de autenticidad es un documento mediante el cual el estudiante manifiesta que el contenido presentado en el Reporte Final de Estadía es resultado de su trabajo académico y profesional. Además, puede utilizarse para aclarar situaciones relacionadas con información confidencial, datos simulados o restricciones de divulgación establecidas por la unidad económica. Este apartado contribuye a garantizar la integridad y transparencia del trabajo realizado. Para conocer el formato y lineamientos aplicables consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. También puedes solicitar orientación a tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["declaratoria de autenticidad","que es la declaratoria de autenticidad","como hacer la declaratoria de autenticidad","para que sirve la declaratoria de autenticidad","declaratoria de autenticidad estadia","ejemplo de declaratoria de autenticidad","contenido de declaratoria","como redactar la declaratoria","documento de autenticidad","autenticidad del reporte","declaracion de autenticidad","formato de declaratoria","que poner en la declaratoria","declaratoria del reporte","reporte autentico","declaratoria ejemplo","autenticidad academica","declaratoria institucional","documento de respaldo","requisitos de declaratoria"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debe contener la declaración de uso de herramientas de Inteligencia Artificial en mi Reporte Final de Estadía?','La declaración de uso de herramientas de Inteligencia Artificial debe indicar de forma clara qué herramienta fue utilizada, con qué finalidad se empleó, qué tipo de apoyo proporcionó, cómo se verificó la información generada y cuáles fueron los prompts o instrucciones utilizados cuando sea necesario. También se recomienda conservar evidencia del uso de estas herramientas para posibles revisiones académicas. Para conocer los lineamientos completos consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. Si tienes dudas, puedes comunicarte al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["declaracion de uso de ia","declaracion de inteligencia artificial","que debe contener la declaracion de ia","como hacer la declaracion de ia","declarar uso de chatgpt","declarar uso de inteligencia artificial","uso de ia en estadias","formato declaracion ia","que poner en declaracion de ia","como reportar uso de ia","declaracion de herramientas de ia","uso de chatgpt en reporte","prompts de inteligencia artificial","evidencia de uso de ia","documentar uso de ia","declaracion de chatgpt","declaracion de gemini","declaracion de copilot","uso responsable de ia","requisitos de declaracion de ia"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué deben contener las referencias de mi Reporte Final de Estadía?','Las referencias deben incluir todas las fuentes de información consultadas durante el desarrollo del proyecto, tales como libros, artículos científicos, normas, manuales, páginas web, tesis u otros documentos utilizados como apoyo. Las referencias deben presentarse conforme a las Normas APA vigentes y corresponder únicamente a fuentes que hayan sido consultadas y utilizadas dentro del reporte. Para conocer ejemplos y lineamientos específicos consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. También puedes solicitar orientación a tu asesor académico o Dirección de Carrera.','alumnos',true,'["referencias del reporte","que deben contener las referencias","como hacer referencias","referencias apa","bibliografia del reporte","como citar fuentes","referencias de estadia","ejemplo de referencias","como elaborar referencias","bibliografia apa","fuentes de informacion","referencias bibliograficas","como poner referencias","referencias academicas","formato apa referencias","citas y referencias","documentar fuentes","fuentes consultadas","requisitos de referencias","bibliografia del proyecto"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué puedo incluir en los anexos de mi Reporte Final de Estadía?','Los anexos son documentos complementarios que respaldan el desarrollo del proyecto y permiten ampliar la información presentada en el reporte. Pueden incluir fotografías, diagramas, formatos, manuales, encuestas, bitácoras, evidencias, capturas de pantalla, resultados detallados, planos, tablas extensas o cualquier documento que contribuya a comprender mejor el trabajo realizado. Los anexos deben estar relacionados directamente con el proyecto y presentarse de manera ordenada. Para conocer más detalles consulta la Guía para el Reporte Final de Estadía en: https://drive.google.com/file/d/1VbIKs8--m0KZBWqN-zF-5qQ6Axtk6HQu/view?usp=sharing. También puedes solicitar apoyo a tu asesor académico o Dirección de Carrera.','alumnos',true,'["anexos del reporte","que puedo poner en anexos","que son los anexos","como hacer anexos","anexos de estadia","evidencias del proyecto","documentos anexos","fotografias en anexos","capturas en anexos","manuales en anexos","encuestas en anexos","bitacoras en anexos","diagramas en anexos","contenido de anexos","como elaborar anexos","ejemplo de anexos","documentacion complementaria","anexos del proyecto","que incluir en anexos","requisitos de anexos"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué es la Carta de Aceptación de Estadía?','La Carta de Aceptación de Estadía es el documento mediante el cual una empresa o unidad económica confirma oficialmente que acepta a un estudiante de la Universidad Tecnológica de Tula-Tepeji para realizar su estadía profesional. Este documento forma parte de la documentación requerida para iniciar formalmente el proceso de estadía y debe elaborarse en hoja membretada de la empresa. Puedes consultar un ejemplo de este formato en: https://docs.google.com/document/d/1mhd9mjoJnR0TRGISL2O9Pvx_gztVj4CV/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true. Si tienes dudas, puedes solicitar orientación a tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["que es la carta de aceptacion","carta de aceptacion de estadia","para que sirve la carta de aceptacion","que significa carta de aceptacion","aceptacion de empresa","documento de aceptacion","empresa me acepta para estadia","carta de aceptacion profesional","carta para iniciar estadia","aceptacion de practicas","documento de estadias","carta de empresa","que necesito para la carta de aceptacion","como funciona la carta de aceptacion","carta de aceptacion de la empresa","aceptacion de unidad economica","documento de ingreso a estadia","que es una carta de aceptacion de empresa","aceptacion para realizar estadia","carta requerida para estadias"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Quién debe emitir la Carta de Aceptación de Estadía?','La Carta de Aceptación de Estadía debe ser emitida por la empresa o unidad económica donde el estudiante realizará su estadía. El documento debe elaborarse en hoja membretada de la organización y ser firmado por una persona autorizada dentro de la empresa. Cuando aplique, también deberá incluir el sello institucional correspondiente. Puedes consultar un ejemplo del formato en: https://docs.google.com/document/d/1mhd9mjoJnR0TRGISL2O9Pvx_gztVj4CV/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true. Para mayores informes puedes comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["quien emite la carta de aceptacion","quien hace la carta de aceptacion","quien firma la carta de aceptacion","la universidad hace la carta de aceptacion","la empresa hace la carta de aceptacion","quien entrega la carta de aceptacion","responsable de la carta de aceptacion","quien autoriza la carta","quien debe firmar la carta","empresa receptora carta de aceptacion","carta emitida por la empresa","carta de aceptacion firmada","quien genera la carta","carta oficial de aceptacion","quien redacta la carta","autoridad que firma la carta","carta de aceptacion de estadia empresa","responsable de emitir la carta","carta membretada de empresa","quien valida la carta de aceptacion"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué información debe contener la Carta de Aceptación de Estadía?','La Carta de Aceptación de Estadía debe elaborarse en hoja membretada de la empresa y contener, entre otros datos, la fecha de emisión, nombre completo del estudiante, matrícula, programa educativo, periodo de estadía, área o departamento donde realizará sus actividades, así como el nombre, cargo, firma y sello de la persona responsable que autoriza la aceptación. Es importante verificar que toda la información sea correcta antes de entregarla. Puedes consultar un ejemplo oficial en: https://docs.google.com/document/d/1mhd9mjoJnR0TRGISL2O9Pvx_gztVj4CV/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["que debe contener la carta de aceptacion","datos de la carta de aceptacion","informacion de la carta de aceptacion","contenido de la carta de aceptacion","como llenar la carta de aceptacion","requisitos de la carta de aceptacion","que datos lleva la carta","ejemplo de carta de aceptacion","estructura de la carta de aceptacion","como hacer la carta de aceptacion","que poner en la carta de aceptacion","partes de la carta de aceptacion","elementos de la carta de aceptacion","datos obligatorios de la carta","formato de carta de aceptacion","informacion requerida en la carta","carta de aceptacion ejemplo","campos de la carta de aceptacion","que lleva la carta de empresa","documento de aceptacion requisitos"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Dónde puedo obtener el formato de la Carta de Aceptación de Estadía?','Puedes consultar un ejemplo del formato de Carta de Aceptación de Estadía en el siguiente enlace: https://docs.google.com/document/d/1mhd9mjoJnR0TRGISL2O9Pvx_gztVj4CV/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true. También puedes solicitar orientación a tu asesor académico, Dirección de Carrera o al Departamento de Estadías e Inserción Laboral para asegurarte de que la carta cumpla con los requisitos institucionales antes de entregarla. Para mayores informes puedes comunicarte al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["donde consigo la carta de aceptacion","donde descargar la carta de aceptacion","formato de carta de aceptacion","ejemplo de carta de aceptacion","plantilla de carta de aceptacion","carta de aceptacion pdf","carta de aceptacion word","como obtener la carta de aceptacion","descargar formato de aceptacion","modelo de carta de aceptacion","documento de aceptacion","donde encuentro la carta","formato oficial de aceptacion","carta de aceptacion ejemplo","plantilla para empresa","archivo de carta de aceptacion","carta de aceptacion estadia formato","como conseguir el formato","link carta de aceptacion","carta de aceptacion para empresa"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La Carta de Aceptación de Estadía debe llevar firma y sello?','Sí. La Carta de Aceptación de Estadía debe estar firmada por la persona responsable o autorizada dentro de la empresa o unidad económica. Además, cuando la organización cuente con sello institucional, se recomienda incluirlo para fortalecer la validez del documento. Antes de entregarla verifica que la información esté completa y correctamente firmada. Puedes consultar un ejemplo en: https://docs.google.com/document/d/1mhd9mjoJnR0TRGISL2O9Pvx_gztVj4CV/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["la carta lleva sello","la carta lleva firma","firma y sello carta de aceptacion","debe estar firmada la carta","la empresa debe sellar la carta","es obligatorio el sello","es obligatoria la firma","requisitos de firma en carta","carta firmada por empresa","carta con sello institucional","validacion de carta de aceptacion","firma del responsable","carta de aceptacion sellada","documento firmado","firma del representante","la carta necesita sello","como validar la carta","firma autorizada carta","documento con firma y sello","requisitos de validacion de la carta"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cuándo debo entregar mi Carta de Aceptación de Estadía?','Se recomienda entregar la Carta de Aceptación de Estadía tan pronto como la empresa confirme oficialmente tu incorporación al proyecto o área asignada. Esto permitirá avanzar oportunamente con los procesos administrativos y académicos relacionados con tu estadía. Si tienes dudas sobre fechas o procedimientos específicos, consulta a tu asesor académico, Dirección de Carrera o comunícate con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["cuando entregar la carta de aceptacion","fecha de entrega carta de aceptacion","cuando debo entregar la carta","plazo de entrega de carta","en que momento entrego la carta","tiempo para entregar carta de aceptacion","cuando presentar la carta","entrega de carta de aceptacion","fecha limite carta de aceptacion","cuando llevar la carta","proceso de entrega de carta","cuando se entrega la aceptacion","documentacion de estadia","tramite de carta de aceptacion","entregar carta a vinculacion","inicio de estadia carta","carta antes de iniciar estadia","cuando presentar aceptacion","momento de entregar la carta","requisitos para iniciar estadia"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');   
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué es la Carta de Acuerdos de Estadía?','La Carta de Acuerdos de Estadía es el documento mediante el cual se formaliza la asignación del asesor académico y se establecen los compromisos y responsabilidades que asumirán tanto el estudiante como el asesor durante el proceso de estadía. Este documento permite dar seguimiento académico al proyecto y al desarrollo del Reporte Final de Estadía. Puedes consultar el formato en: https://docs.google.com/document/d/1XYb0j9-afrmgOTAAQgjKYy0rgM1zJkh2/edit?usp=sharing&rtpof=true&sd=true. Si tienes dudas, puedes comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["que es la carta de acuerdos","carta de acuerdos de estadia","para que sirve la carta de acuerdos","documento de acuerdos","acuerdos de estadia","carta de compromisos","carta de seguimiento","que significa carta de acuerdos","documento de estadias","carta de acuerdos ejemplo","formato carta de acuerdos","acuerdos alumno asesor","carta oficial de acuerdos","carta de responsabilidades","documento de seguimiento academico","compromisos de estadia","carta para estadias","acuerdos del proyecto","que contiene la carta de acuerdos","carta de acuerdos uttt"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Para qué sirve la Carta de Acuerdos de Estadía?','La Carta de Acuerdos de Estadía sirve para establecer formalmente los compromisos y responsabilidades del estudiante y del asesor académico durante el desarrollo de la estadía. También permite definir las bases para el seguimiento del proyecto y la elaboración del Reporte Final de Estadía. Puedes consultar el formato en: https://docs.google.com/document/d/1XYb0j9-afrmgOTAAQgjKYy0rgM1zJkh2/edit?usp=sharing&rtpof=true&sd=true.','alumnos',true,'["para que sirve la carta de acuerdos","funcion de la carta de acuerdos","objetivo de la carta de acuerdos","importancia de la carta de acuerdos","utilidad de la carta de acuerdos","porque firmar la carta de acuerdos","proposito de la carta de acuerdos","beneficios de la carta de acuerdos","seguimiento de estadia","control de estadia","documento de compromisos","acuerdos con asesor","responsabilidades de estadia","proceso de estadia","formalizacion de acuerdos","acuerdos academicos","seguimiento academico","compromisos del alumno","funcion del documento","documento oficial de estadia"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Quiénes deben firmar la Carta de Acuerdos de Estadía?','La Carta de Acuerdos de Estadía debe ser firmada por el estudiante y el asesor académico asignado. Mediante estas firmas ambas partes aceptan los compromisos y responsabilidades establecidos para el desarrollo de la estadía y el seguimiento académico del proyecto. Puedes consultar el formato en: https://docs.google.com/document/d/1XYb0j9-afrmgOTAAQgjKYy0rgM1zJkh2/edit?usp=sharing&rtpof=true&sd=true.','alumnos',true,'["quien firma la carta de acuerdos","firmas de la carta de acuerdos","quien debe firmar la carta","asesor academico firma","alumno firma carta","responsables de firmar","firma del estudiante","firma del asesor","firmar carta de acuerdos","firmas obligatorias","validacion de la carta","quien autoriza la carta","carta firmada","requisitos de firma","firma de estadia","formalizar la carta","firma del documento","firmas oficiales","documento firmado","quienes participan en la carta"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué información contiene la Carta de Acuerdos de Estadía?','La Carta de Acuerdos de Estadía generalmente incluye información del estudiante, matrícula, programa educativo, nombre del asesor académico, fechas correspondientes al proceso de estadía y los compromisos y responsabilidades que ambas partes asumirán durante el desarrollo del proyecto. Se recomienda revisar cuidadosamente la información antes de firmar el documento. Puedes consultar el formato en: https://docs.google.com/document/d/1XYb0j9-afrmgOTAAQgjKYy0rgM1zJkh2/edit?usp=sharing&rtpof=true&sd=true.','alumnos',true,'["que contiene la carta de acuerdos","informacion de la carta de acuerdos","datos de la carta de acuerdos","que lleva la carta de acuerdos","contenido de la carta de acuerdos","estructura de la carta de acuerdos","partes de la carta de acuerdos","datos del alumno en la carta","compromisos de la carta","formato de la carta de acuerdos","que incluye la carta","elementos de la carta","informacion del documento","datos obligatorios","contenido del formato","estructura del formato","documento de acuerdos","campos de la carta","que revisar en la carta","datos del asesor academico"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Dónde puedo consultar el formato de la Carta de Acuerdos de Estadía?','Puedes consultar el formato de la Carta de Acuerdos de Estadía en el siguiente enlace: https://docs.google.com/document/d/1XYb0j9-afrmgOTAAQgjKYy0rgM1zJkh2/edit?usp=sharing&rtpof=true&sd=true. También puedes solicitar orientación a tu asesor académico, Dirección de Carrera o al Departamento de Estadías e Inserción Laboral para resolver cualquier duda relacionada con este documento.','alumnos',true,'["donde consigo la carta de acuerdos","formato de carta de acuerdos","descargar carta de acuerdos","plantilla carta de acuerdos","ejemplo de carta de acuerdos","modelo de carta de acuerdos","documento carta de acuerdos","archivo carta de acuerdos","link carta de acuerdos","donde encuentro la carta","carta de acuerdos pdf","carta de acuerdos word","consultar carta de acuerdos","obtener carta de acuerdos","descargar formato","documento de acuerdos","plantilla de estadia","carta de acuerdos ejemplo","formato oficial","carta de acuerdos uttt"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La Carta de Acuerdos de Estadía es obligatoria?','Sí. La Carta de Acuerdos de Estadía forma parte de la documentación utilizada para formalizar el seguimiento académico del proyecto y establecer los compromisos entre el estudiante y el asesor académico. Se recomienda completar y firmar este documento conforme a las indicaciones institucionales. Para más información consulta el formato oficial o comunícate con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["es obligatoria la carta de acuerdos","debo entregar la carta de acuerdos","es necesaria la carta de acuerdos","carta de acuerdos obligatoria","tengo que firmar la carta","requisito carta de acuerdos","documento obligatorio","necesito la carta de acuerdos","tramite obligatorio","proceso de estadia","documentacion obligatoria","formalizar estadia","carta requerida","requisito de estadias","obligatorio firmar la carta","documento necesario","papeles de estadia","requisito institucional","obligatorio para estadia","necesaria para estadias"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');   
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué es la Minuta de Acuerdos de Estadía?','La Minuta de Acuerdos de Estadía es el documento mediante el cual se establecen formalmente las condiciones, acuerdos y características específicas bajo las cuales se desarrollará la estadía. En este documento se registran aspectos como la problemática a atender, el proyecto a desarrollar, los entregables esperados, las actividades del estudiante, el calendario de asesorías y otros elementos necesarios para el seguimiento académico y profesional de la estadía. Puedes consultar el formato en: https://docs.google.com/document/d/1UrP1vWY_e41z1A132OX8QAcwwUfYHS2P/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true. Si tienes dudas, puedes comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["que es la minuta de acuerdos","minuta de acuerdos de estadia","para que sirve la minuta","que significa minuta de acuerdos","documento minuta de acuerdos","minuta de estadia","que es una minuta de estadia","minuta del proyecto","documento de acuerdos","acuerdos de estadia","minuta ejemplo","formato de minuta","que contiene la minuta","minuta academica","minuta con la empresa","minuta con asesor","minuta de seguimiento","documento oficial de estadia","minuta uttt","que es la minuta"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Para qué sirve la Minuta de Acuerdos de Estadía?','La Minuta de Acuerdos de Estadía sirve para definir y dejar por escrito los acuerdos relacionados con el desarrollo de la estadía, incluyendo la problemática a atender, el alcance del proyecto, los entregables esperados, las actividades del estudiante, las asesorías académicas y otros aspectos relevantes para el seguimiento y evaluación del proyecto. Este documento ayuda a que todas las partes involucradas tengan claridad sobre las responsabilidades y objetivos establecidos. Puedes consultar el formato en: https://docs.google.com/document/d/1UrP1vWY_e41z1A132OX8QAcwwUfYHS2P/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["para que sirve la minuta de acuerdos","funcion de la minuta","objetivo de la minuta","importancia de la minuta","utilidad de la minuta","porque hacer una minuta","para que es la minuta","beneficios de la minuta","seguimiento de estadia","acuerdos del proyecto","control del proyecto","documento de seguimiento","proposito de la minuta","funcion del documento","minuta para estadias","formalizar acuerdos","acuerdos con la empresa","acuerdos con asesor","seguimiento academico","documento de acuerdos"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Quiénes participan en la Minuta de Acuerdos de Estadía?','En la Minuta de Acuerdos de Estadía participan principalmente el estudiante, el asesor académico de la Universidad y el asesor de la unidad económica donde se desarrolla la estadía. Estas personas intervienen en la definición de acuerdos, seguimiento del proyecto y validación de los compromisos establecidos durante la estadía. Puedes consultar el formato oficial en: https://docs.google.com/document/d/1UrP1vWY_e41z1A132OX8QAcwwUfYHS2P/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["quienes participan en la minuta","quien firma la minuta","participantes de la minuta","quien interviene en la minuta","asesor academico minuta","asesor de empresa minuta","estudiante minuta","responsables de la minuta","firmantes de la minuta","personas de la minuta","quien llena la minuta","quien realiza la minuta","participantes del proyecto","actores de la minuta","quienes hacen la minuta","integrantes de la minuta","involucrados en la minuta","responsables del documento","quienes aparecen en la minuta","firmas de la minuta"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué información se define en la Minuta de Acuerdos de Estadía?','La Minuta de Acuerdos permite definir información importante como la problemática identificada por la unidad económica, el nombre del proyecto, el alcance del proyecto de estadía, los entregables esperados, las actividades que realizará el estudiante, el horario asignado, la fecha de conclusión del reporte, las asesorías académicas y diversos acuerdos relacionados con el desarrollo de la estadía. Puedes consultar el formato en: https://docs.google.com/document/d/1UrP1vWY_e41z1A132OX8QAcwwUfYHS2P/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["que informacion contiene la minuta","que se define en la minuta","datos de la minuta","contenido de la minuta","que lleva la minuta","informacion de la minuta","estructura de la minuta","partes de la minuta","campos de la minuta","datos del proyecto","informacion del proyecto","contenido del formato","elementos de la minuta","que incluye la minuta","datos obligatorios de la minuta","formato de minuta","informacion requerida","estructura del documento","que registrar en la minuta","datos de estadia"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué actividades deben registrarse en la Minuta de Acuerdos de Estadía?','En la Minuta de Acuerdos deben registrarse las actividades que realizará el estudiante para lograr los objetivos y entregables del proyecto de estadía. Estas actividades deben relacionarse directamente con el trabajo que se desarrollará dentro de la unidad económica y servirán como referencia para el seguimiento y evaluación del proyecto. Puedes consultar el formato en: https://docs.google.com/document/d/1UrP1vWY_e41z1A132OX8QAcwwUfYHS2P/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true. Si tienes dudas sobre las actividades a registrar, consulta a tu asesor académico o asesor de la unidad económica.','alumnos',true,'["actividades de la minuta","que actividades registrar","actividades del proyecto","actividades de estadia","que poner en actividades","registro de actividades","actividades del estudiante","trabajo del estudiante","actividades del proyecto de estadia","actividades a realizar","como llenar actividades","actividades de la minuta de acuerdos","actividades del formato","acciones del proyecto","tareas de estadia","que debe hacer el estudiante","plan de actividades","actividades comprometidas","actividades acordadas","trabajo a desarrollar"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');   
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué es el alcance del proyecto de estadía?','El alcance del proyecto de estadía define los límites, objetivos, resultados esperados y actividades principales que serán desarrolladas durante el periodo de estadía. Este apartado permite establecer con claridad qué se realizará dentro de la unidad económica y qué productos o beneficios se espera obtener al finalizar el proyecto. El alcance debe quedar definido y acordado entre el estudiante, el asesor académico y el asesor de la unidad económica dentro de la Minuta de Acuerdos. Puedes consultar el formato en: https://docs.google.com/document/d/1UrP1vWY_e41z1A132OX8QAcwwUfYHS2P/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["que es el alcance del proyecto","alcance del proyecto de estadia","que significa alcance","como definir el alcance","alcance de estadia","que poner en alcance","alcance del proyecto ejemplo","definicion de alcance","limites del proyecto","objetivos del alcance","alcance del trabajo","alcance del proyecto final","como redactar el alcance","que incluye el alcance","alcance de actividades","alcance del proyecto profesional","alcance de la estadia","resultados esperados del proyecto","que debe contener el alcance","alcance del formato"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué son los entregables del proyecto de estadía?','Los entregables son los productos, resultados, documentos, prototipos, mejoras, sistemas, reportes o evidencias que el estudiante se compromete a generar como resultado de su proyecto de estadía. Estos deben quedar claramente definidos en la Minuta de Acuerdos para facilitar el seguimiento y evaluación del proyecto. Puedes consultar el formato en: https://docs.google.com/document/d/1UrP1vWY_e41z1A132OX8QAcwwUfYHS2P/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["que son los entregables","entregables del proyecto","que es un entregable","entregables de estadia","productos entregables","resultado del proyecto","que debo entregar","entregables ejemplo","entregables del trabajo","que poner en entregables","entregables de la minuta","productos del proyecto","resultados comprometidos","evidencias del proyecto","documentos entregables","proyecto entregable","productos finales","entregables de estadia profesional","resultado esperado","entregables del formato"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Se deben programar asesorías académicas en la Minuta de Acuerdos?','Sí. La Minuta de Acuerdos contempla un apartado específico para programar las asesorías académicas que recibirá el estudiante durante su estadía. En este apartado se registran fechas, horarios y modalidad de atención, ya sea presencial o virtual. Estas asesorías permiten dar seguimiento al proyecto y al Reporte Final de Estadía. Puedes consultar el formato en: https://docs.google.com/document/d/1UrP1vWY_e41z1A132OX8QAcwwUfYHS2P/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["asesorias academicas","programar asesorias","asesorias en la minuta","seguimiento academico","fechas de asesoria","asesorias de estadia","asesor academico reuniones","asesorias virtuales","asesorias presenciales","calendario de asesorias","asesorias del proyecto","programacion de asesorias","asesorias obligatorias","seguimiento del reporte","asesorias con asesor academico","reuniones de estadia","asesorias durante estadia","agenda de asesorias","horarios de asesoria","atencion academica"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La Minuta de Acuerdos contempla el uso de Inteligencia Artificial?','Sí. La Minuta de Acuerdos incluye una cláusula de uso ético de Inteligencia Artificial donde se establecen responsabilidades para el estudiante, el asesor académico y el asesor de la unidad económica. Entre otros aspectos, se indica que el estudiante debe utilizar la IA únicamente como apoyo complementario, declarar su uso en el Reporte Final de Estadía y respetar la confidencialidad de la información de la empresa. Para más información consulta la Minuta de Acuerdos y los lineamientos institucionales de uso ético de IA. :contentReference[oaicite:0]{index=0}','alumnos',true,'["uso de ia en la minuta","inteligencia artificial en estadia","clausula de ia","ia en estadias","uso etico de ia","chatgpt en estadia","puedo usar inteligencia artificial","uso de ia en proyecto","lineamientos de ia","declaracion de ia","restricciones de ia","uso responsable de ia","herramientas de inteligencia artificial","ia en reporte de estadia","normas de ia","reglas de inteligencia artificial","uso academico de ia","inteligencia artificial y estadia","puedo usar chatgpt","clausula de inteligencia artificial"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La empresa puede autorizar o restringir el uso de Inteligencia Artificial durante la estadía?','Sí. Dentro de la Minuta de Acuerdos existe un apartado donde la unidad económica puede autorizar, restringir o no permitir el uso de herramientas de Inteligencia Artificial con información propia de la empresa. Es importante respetar las políticas de confidencialidad y los acuerdos establecidos por la organización donde realizas tu estadía. Puedes consultar el formato en: https://docs.google.com/document/d/1UrP1vWY_e41z1A132OX8QAcwwUfYHS2P/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["la empresa puede prohibir la ia","restricciones de ia","autorizacion de ia","uso de chatgpt en empresa","puedo usar ia en mi estadia","empresa autoriza inteligencia artificial","empresa restringe ia","politicas de ia","uso de ia con informacion de empresa","confidencialidad e ia","chatgpt en empresa","ia permitida en estadia","restricciones de chatgpt","uso de herramientas de ia","permiso para usar ia","empresa permite ia","prohibicion de ia","uso de inteligencia artificial en empresa","autorizacion de herramientas de ia","reglas de ia en estadia"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La empresa debe proporcionar inducción y medidas de seguridad durante la estadía?','Sí. La Minuta de Acuerdos contempla un apartado donde la unidad económica puede establecer la inducción que recibirá el estudiante, así como las medidas de seguridad, reglamentos internos, equipo de protección personal y lineamientos que deberán cumplirse durante el desarrollo de la estadía. Es importante atender todas las indicaciones proporcionadas por la empresa para garantizar una estancia segura y adecuada. Puedes consultar el formato en: https://docs.google.com/document/d/1UrP1vWY_e41z1A132OX8QAcwwUfYHS2P/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["induccion de estadia","medidas de seguridad en estadia","capacitacion inicial","seguridad en la empresa","equipo de proteccion","induccion de empresa","reglamento interno empresa","seguridad industrial estadia","proteccion personal","capacitacion de ingreso","normas de seguridad","equipo de seguridad","lineamientos de empresa","prevencion de riesgos","seguridad para estudiantes","induccion laboral","capacitacion en empresa","politicas de seguridad","seguridad durante la estadia","medidas de proteccion"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La empresa proporcionará recursos para el desarrollo de la estadía?','La Minuta de Acuerdos incluye un apartado para registrar si la unidad económica proporcionará recursos para el desarrollo del proyecto de estadía. Estos recursos pueden variar dependiendo de la naturaleza del proyecto y de las condiciones establecidas por la empresa. Se recomienda revisar este apartado antes de iniciar actividades para tener claridad sobre los apoyos disponibles. Puedes consultar el formato en: https://docs.google.com/document/d/1UrP1vWY_e41z1A132OX8QAcwwUfYHS2P/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["recursos para estadia","apoyo de la empresa","herramientas para estadia","la empresa proporciona recursos","materiales para proyecto","equipo para estadia","recursos del proyecto","apoyo para desarrollar proyecto","herramientas de trabajo","recursos de la empresa","material para estadia","equipo proporcionado","apoyo institucional empresa","recursos para estudiante","insumos del proyecto","apoyo tecnico","equipo de trabajo","materiales de apoyo","recursos disponibles","herramientas del proyecto"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Se puede recibir apoyo económico durante la estadía?','Sí. La Minuta de Acuerdos contempla un apartado donde la unidad económica puede indicar si otorgará o no algún apoyo económico al estudiante durante el periodo de estadía. Este apoyo depende exclusivamente de las políticas y condiciones establecidas por cada empresa, por lo que no todas las organizaciones ofrecen este beneficio. Puedes consultar el formato en: https://docs.google.com/document/d/1UrP1vWY_e41z1A132OX8QAcwwUfYHS2P/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["apoyo economico en estadia","me pagan la estadia","beca de estadia","apoyo de la empresa","estadia remunerada","dinero durante estadia","empresa paga estadia","compensacion economica","ayuda economica","estadia con apoyo economico","apoyo monetario","estadia pagada","apoyo financiero","empresa da apoyo economico","recibir dinero en estadia","beneficio economico","apoyo durante estadia","estimulo economico","pago por estadia","ayuda de empresa"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La Minuta de Acuerdos debe estar firmada?','Sí. La Minuta de Acuerdos debe ser firmada por el estudiante, el asesor académico y el asesor de la unidad económica. Las firmas permiten formalizar los acuerdos establecidos para el desarrollo de la estadía y dejan constancia de que todas las partes conocen y aceptan las condiciones definidas en el documento. Puedes consultar el formato oficial en: https://docs.google.com/document/d/1UrP1vWY_e41z1A132OX8QAcwwUfYHS2P/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["firmas de la minuta","quien firma la minuta","la minuta debe estar firmada","firmar minuta de acuerdos","firmas obligatorias","firma del estudiante","firma del asesor academico","firma del asesor industrial","validacion de la minuta","requisitos de firma","documento firmado","formalizar la minuta","firmas del proyecto","responsables de firmar","autorizacion de la minuta","firmas oficiales","minuta firmada","firma de acuerdos","quienes firman la minuta","firma del documento"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué información de contacto debe registrarse en la Minuta de Acuerdos?','La Minuta de Acuerdos contempla el registro de información de contacto de las personas involucradas en el proceso de estadía, incluyendo datos del estudiante, asesor académico y asesor de la unidad económica. Esta información facilita la comunicación, el seguimiento del proyecto y la coordinación de asesorías o actividades relacionadas con la estadía. Es importante verificar que los datos proporcionados sean correctos y se mantengan actualizados. Puedes consultar el formato en: https://docs.google.com/document/d/1UrP1vWY_e41z1A132OX8QAcwwUfYHS2P/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["datos de contacto minuta","informacion de contacto","telefono en la minuta","correo en la minuta","datos del asesor academico","datos del asesor industrial","contacto del estudiante","informacion personal minuta","contactos del proyecto","datos para seguimiento","correo del asesor","telefono del asesor","informacion de participantes","datos de estadia","registro de contactos","comunicacion del proyecto","datos obligatorios de contacto","informacion de responsables","contacto para estadia","datos de comunicacion"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué es la Carta Compromiso de Estadía?','La Carta Compromiso de Estadía es el documento mediante el cual el estudiante manifiesta que conoce, comprende y acepta las obligaciones, responsabilidades, lineamientos y disposiciones institucionales relacionadas con el proceso de estadía. Al firmarla, el estudiante se compromete a cumplir con las actividades académicas, administrativas y profesionales establecidas durante el desarrollo de su proyecto. Puedes consultar el formato en: https://docs.google.com/document/d/1An0qNOLRw7ydJjy6Y0KM4nKTq7DKatuS/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true. Para más información puedes acudir con tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["que es la carta compromiso","carta compromiso de estadia","documento carta compromiso","que significa carta compromiso","para que sirve la carta compromiso","compromiso de estadia","carta compromiso uttt","documento de compromiso","acuerdo de compromiso","formato carta compromiso","carta compromiso ejemplo","objetivo de la carta compromiso","importancia de la carta compromiso","compromisos del estudiante","documento oficial de compromiso","responsabilidades de estadia","aceptacion de compromisos","carta compromiso alumnos","carta de compromiso estadia","que es la carta compromiso de estadia"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Para qué sirve la Carta Compromiso de Estadía?','La Carta Compromiso de Estadía sirve para formalizar la aceptación de las obligaciones y responsabilidades que el estudiante deberá cumplir durante el desarrollo de su estadía. A través de este documento se establece el compromiso de respetar la normatividad institucional, los lineamientos de estadía y las disposiciones aplicables dentro de la unidad económica donde se realizará el proyecto. Puedes consultar el formato en: https://docs.google.com/document/d/1An0qNOLRw7ydJjy6Y0KM4nKTq7DKatuS/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["para que sirve la carta compromiso","funcion de la carta compromiso","objetivo de la carta compromiso","importancia de la carta compromiso","utilidad de la carta compromiso","proposito de la carta compromiso","beneficios de la carta compromiso","porque firmar la carta compromiso","para que es la carta compromiso","documento de compromiso","formalizar estadia","compromisos de estadia","responsabilidades del alumno","seguimiento de estadia","proceso de estadia","documento obligatorio","carta compromiso funcion","utilidad del documento","objetivo del compromiso","compromiso institucional"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Quién debe firmar la Carta Compromiso de Estadía?','La Carta Compromiso de Estadía debe ser firmada por el estudiante, quien mediante su firma acepta los compromisos, obligaciones y responsabilidades establecidos en el documento. Se recomienda verificar que la información registrada sea correcta antes de firmarla y entregarla como parte de la documentación del proceso de estadía. Puedes consultar el formato en: https://docs.google.com/document/d/1An0qNOLRw7ydJjy6Y0KM4nKTq7DKatuS/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["quien firma la carta compromiso","firma de la carta compromiso","quien debe firmar","firma del estudiante","responsable de firmar","firmar carta compromiso","firmas del documento","firma obligatoria","validacion de carta compromiso","quien autoriza la carta","requisitos de firma","documento firmado","carta compromiso firmada","firma del alumno","formalizacion del compromiso","firma oficial","aceptacion del compromiso","firmante de la carta","responsable del documento","firma de estadia"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué información contiene la Carta Compromiso de Estadía?','La Carta Compromiso de Estadía contiene información relacionada con las obligaciones y compromisos que el estudiante acepta cumplir durante el desarrollo de su estadía. Entre otros aspectos, incluye disposiciones sobre normatividad institucional, confidencialidad, seguridad e higiene, cumplimiento de actividades académicas, responsabilidades dentro de la unidad económica y consecuencias derivadas de su incumplimiento. Puedes consultar el formato en: https://docs.google.com/document/d/1An0qNOLRw7ydJjy6Y0KM4nKTq7DKatuS/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["que contiene la carta compromiso","informacion de la carta compromiso","datos de la carta compromiso","contenido de la carta compromiso","que lleva la carta compromiso","estructura de la carta compromiso","partes de la carta compromiso","elementos de la carta compromiso","datos del documento","campos de la carta compromiso","contenido del formato","informacion requerida","datos obligatorios","estructura del documento","informacion del estudiante","compromisos de la carta","contenido del compromiso","formato carta compromiso","que incluye la carta","datos del formato"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Dónde puedo consultar el formato de la Carta Compromiso de Estadía?','Puedes consultar el formato de la Carta Compromiso de Estadía en el siguiente enlace: https://docs.google.com/document/d/1An0qNOLRw7ydJjy6Y0KM4nKTq7DKatuS/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true. Si tienes dudas sobre su llenado o entrega, puedes acudir con tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["donde consultar carta compromiso","formato carta compromiso","descargar carta compromiso","plantilla carta compromiso","ejemplo carta compromiso","modelo carta compromiso","archivo carta compromiso","link carta compromiso","consultar carta compromiso","documento carta compromiso","carta compromiso pdf","carta compromiso word","obtener carta compromiso","descargar formato","formato oficial","documento de compromiso","carta compromiso ejemplo","donde encuentro la carta","plantilla de estadia","carta compromiso uttt"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La Carta Compromiso de Estadía es obligatoria?','Sí. La Carta Compromiso de Estadía forma parte de la documentación requerida dentro del proceso de estadía y permite formalizar la aceptación de las responsabilidades y obligaciones que deberá cumplir el estudiante durante el desarrollo de su proyecto. Su entrega es importante para continuar con los trámites correspondientes. Puedes consultar el formato en: https://docs.google.com/document/d/1An0qNOLRw7ydJjy6Y0KM4nKTq7DKatuS/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["es obligatoria la carta compromiso","debo entregar la carta compromiso","es necesaria la carta compromiso","documento obligatorio","requisito de estadia","carta compromiso obligatoria","necesito la carta compromiso","tramite obligatorio","documentacion obligatoria","requisito institucional","papeles de estadia","documento requerido","es necesario firmarla","obligatorio para estadia","documento necesario","formalizar estadia","requisito administrativo","entrega de carta compromiso","carta requerida","obligacion de firmar"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué compromisos acepta el estudiante al firmar la Carta Compromiso?','Al firmar la Carta Compromiso de Estadía, el estudiante acepta cumplir las disposiciones institucionales aplicables al proceso de estadía, respetar los lineamientos académicos, atender las indicaciones de sus asesores, cumplir con las actividades asignadas, actuar con responsabilidad profesional y observar las políticas establecidas por la unidad económica donde desarrollará su proyecto. Puedes consultar el formato en: https://docs.google.com/document/d/1An0qNOLRw7ydJjy6Y0KM4nKTq7DKatuS/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["compromisos del estudiante","que acepto al firmar","responsabilidades del estudiante","obligaciones de estadia","compromisos de la carta","que debo cumplir","responsabilidades en estadia","obligaciones del alumno","compromiso institucional","deberes del estudiante","que compromisos tengo","responsabilidades academicas","compromisos de estadia","aceptacion de responsabilidades","obligaciones del proyecto","deberes en estadia","que implica firmar","compromisos academicos","responsabilidades profesionales","acuerdo de compromisos"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La Carta Compromiso establece obligaciones relacionadas con la confidencialidad?','Sí. La Carta Compromiso de Estadía establece que el estudiante debe actuar con responsabilidad respecto a la información a la que tenga acceso durante su estadía. Esto incluye respetar las políticas de confidencialidad de la unidad económica y hacer un uso adecuado de la información institucional o empresarial relacionada con su proyecto. Puedes consultar el formato en: https://docs.google.com/document/d/1An0qNOLRw7ydJjy6Y0KM4nKTq7DKatuS/edit?usp=sharing&ouid=110777287027882965510&rtpof=true&sd=true.','alumnos',true,'["confidencialidad en estadia","informacion confidencial","guardar confidencialidad","datos de la empresa","politicas de confidencialidad","secreto de informacion","informacion empresarial","confidencialidad del proyecto","uso de informacion","proteger informacion","acceso a informacion","manejo de datos","informacion reservada","obligacion de confidencialidad","politicas de empresa","informacion institucional","responsabilidad sobre informacion","confidencialidad del estudiante","datos confidenciales","acuerdo de confidencialidad"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué es la Carta de Terminación de Estadía?','La Carta de Terminación de Estadía es el documento emitido por la empresa o unidad económica donde el estudiante realizó su estadía, mediante el cual se hace constar que concluyó satisfactoriamente el periodo establecido y las actividades correspondientes a su proyecto. Este documento forma parte de la documentación requerida para concluir el proceso de estadía. Puedes consultar los requisitos de la Carta de Terminación de Estadía en: https://drive.google.com/file/d/11xtGdLUqsA6IZmjdyMNeJC5qn6W6qfUa/view?usp=sharing. Para más información puedes acudir con tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["que es la carta de terminacion","carta de terminacion de estadia","para que sirve la carta de terminacion","documento de terminacion","terminacion de estadia","constancia de termino de estadia","carta final de estadia","documento final de estadia","que significa carta de terminacion","carta de cierre de estadia","termino de estadia","documento de conclusion","carta emitida por la empresa","finalizacion de estadia","carta de liberacion de estadia","comprobante de termino","fin de estadia","carta de conclusion","documento de cierre","carta de terminacion uttt"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué información debe contener la Carta de Terminación de Estadía?','La Carta de Terminación de Estadía debe elaborarse en hoja membretada de la empresa y contener el nombre completo del estudiante sin abreviaturas, matrícula, nombre completo del programa educativo, nombre completo del proyecto, periodo de estadía, fecha de expedición, firma y sello de la empresa cuando corresponda. Es importante verificar que toda la información sea correcta antes de entregarla. Puedes consultar los requisitos de la Carta de Terminación de Estadía en: https://drive.google.com/file/d/11xtGdLUqsA6IZmjdyMNeJC5qn6W6qfUa/view?usp=sharing. Para más información puedes acudir con tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["que debe contener la carta de terminacion","datos de la carta de terminacion","informacion de la carta de terminacion","contenido de la carta de terminacion","que lleva la carta de terminacion","requisitos de la carta de terminacion","estructura de la carta de terminacion","partes de la carta de terminacion","elementos de la carta de terminacion","datos obligatorios","informacion requerida","campos de la carta","como llenar la carta","formato carta de terminacion","contenido del formato","requisitos del documento","datos del estudiante","datos del proyecto","documento de terminacion requisitos","carta de terminacion ejemplo"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿A quién debe dirigirse la Carta de Terminación de Estadía?','La Carta de Terminación de Estadía debe dirigirse a la Mtra. Lucero Manilla Muñoz, Encargada de la Secretaría de Vinculación de la Universidad Tecnológica de Tula-Tepeji. Se recomienda verificar que este dato aparezca correctamente antes de solicitar la emisión del documento. Puedes consultar los requisitos de la Carta de Terminación de Estadía en: https://drive.google.com/file/d/11xtGdLUqsA6IZmjdyMNeJC5qn6W6qfUa/view?usp=sharing. Para más información puedes acudir con tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["a quien va dirigida la carta de terminacion","destinatario de la carta de terminacion","a nombre de quien va la carta","a quien dirigir la carta","dirigir carta de terminacion","mtra lucero manilla muñoz","secretaria de vinculacion","destino de la carta","encabezado de la carta","persona a quien dirigir","receptor de la carta","a quien entregar la carta","carta de terminacion dirigida","nombre para la carta","destinatario oficial","autoridad de vinculacion","dirigir documento de terminacion","encargada de vinculacion","carta para vinculacion","datos del destinatario"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué datos del estudiante deben aparecer en la Carta de Terminación?','La Carta de Terminación debe incluir el nombre completo del estudiante sin abreviaturas, número de matrícula y nombre completo del programa educativo. Se recomienda revisar cuidadosamente que estos datos sean correctos antes de entregar el documento para evitar observaciones o rechazos. Puedes consultar los requisitos de la Carta de Terminación de Estadía en: https://drive.google.com/file/d/11xtGdLUqsA6IZmjdyMNeJC5qn6W6qfUa/view?usp=sharing. Para más información puedes acudir con tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["datos del estudiante","nombre en la carta de terminacion","matricula en la carta","informacion del alumno","datos obligatorios del estudiante","nombre completo del estudiante","que datos lleva del alumno","datos personales en la carta","matricula correcta","programa educativo","datos requeridos del alumno","informacion del estudiante","campos del estudiante","datos academicos","identificacion del estudiante","nombre y matricula","datos del participante","informacion escolar","datos para la carta","registro del estudiante"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué requisitos debe cumplir el periodo de estadía indicado en la Carta de Terminación?','El periodo de estadía indicado en la Carta de Terminación debe incluir fecha de inicio y fecha de término. Además, la duración de la estadía no debe ser menor a 13 semanas ni mayor a 15 semanas. Es importante verificar que las fechas registradas correspondan al periodo autorizado de estadía. Puedes consultar los requisitos de la Carta de Terminación de Estadía en: https://drive.google.com/file/d/11xtGdLUqsA6IZmjdyMNeJC5qn6W6qfUa/view?usp=sharing. Para más información puedes acudir con tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["periodo de estadia","duracion de estadia","13 semanas estadia","15 semanas estadia","fechas de estadia","inicio y termino de estadia","requisitos del periodo","tiempo de estadia","duracion permitida","periodo autorizado","cuantas semanas dura","fecha de inicio","fecha de termino","requisitos de fechas","duracion del proyecto","semanas de estadia","periodo academico","tiempo minimo estadia","tiempo maximo estadia","duracion requerida"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué fecha debe tener la Carta de Terminación?','La fecha de expedición de la Carta de Terminación debe ser posterior a la fecha de término de la estadía, como mínimo un día después. Por ejemplo, si la estadía concluye el 14 de agosto, la carta puede expedirse a partir del 15 de agosto. Es importante verificar este requisito antes de solicitar la emisión del documento. Puedes consultar los requisitos de la Carta de Terminación de Estadía en: https://drive.google.com/file/d/11xtGdLUqsA6IZmjdyMNeJC5qn6W6qfUa/view?usp=sharing. Para más información puedes acudir con tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["fecha de la carta de terminacion","cuando expedir la carta","fecha de expedicion","fecha correcta de la carta","fecha posterior a la estadia","cuando emitir la carta","expedicion de la carta","fecha del documento","requisito de fecha","fecha valida","fecha de conclusion","fecha despues de terminar","cuando solicitar la carta","fecha oficial","expedicion correcta","dia de expedicion","fecha requerida","fecha obligatoria","fecha minima","fecha del formato"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La Carta de Terminación debe llevar firma y sello de la empresa?','Sí. La Carta de Terminación debe estar firmada con tinta azul y sellada por la empresa. En algunos casos de personas físicas o pequeños negocios que no cuentan con sello puede haber excepciones, pero la firma es un requisito indispensable para la validación del documento. Puedes consultar los requisitos de la Carta de Terminación de Estadía en: https://drive.google.com/file/d/11xtGdLUqsA6IZmjdyMNeJC5qn6W6qfUa/view?usp=sharing. Para más información puedes acudir con tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["firma y sello","debe llevar sello","debe llevar firma","firma de la empresa","sello de la empresa","validacion de la carta","documento firmado","carta sellada","requisitos de firma","firma obligatoria","sello obligatorio","firma azul","firma del responsable","empresa firma la carta","validacion empresarial","documento oficial","firma y sello empresa","autorizacion de la carta","carta validada","requisitos del documento"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debo revisar antes de entregar mi Carta de Terminación?','Antes de entregar tu Carta de Terminación debes verificar que tu nombre completo, matrícula, programa educativo, nombre del proyecto, periodo de estadía, fecha de expedición, firma y sello sean correctos. También es importante comprobar que el documento cumpla con todos los requisitos establecidos. Recuerda que si la carta no presenta alguno de los requisitos solicitados, no podrá ser recibida. Puedes consultar los requisitos de la Carta de Terminación de Estadía en: https://drive.google.com/file/d/11xtGdLUqsA6IZmjdyMNeJC5qn6W6qfUa/view?usp=sharing. Para más información puedes acudir con tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["revisar carta de terminacion","validar carta de terminacion","antes de entregar la carta","verificar datos","revision de carta","errores en la carta","comprobar informacion","documento correcto","revision previa","validacion del documento","que revisar","datos correctos","entrega de carta","documentacion final","requisitos antes de entregar","comprobacion de datos","revision de estadias","evitar rechazo","carta correcta","revision de requisitos"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué es la Carpeta Digital de Estadía?','La Carpeta Digital de Estadía es el conjunto de documentos digitales que el estudiante debe integrar y entregar como parte del proceso de estadía y titulación. Esta carpeta contiene la documentación oficial generada durante la estadía y debe cumplir con los requisitos establecidos en la Guía para la Integración de Carpeta Digital de Estadía. Puedes consultar la guía en: https://drive.google.com/file/d/1aaKHWTsOc1ORX1sa6JearcokbC7YINuP/view?usp=sharing. Para más información puedes acudir con tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["que es la carpeta digital","carpeta digital de estadia","que significa carpeta digital","para que sirve la carpeta digital","documentacion digital de estadia","carpeta de estadias","expediente digital de estadia","documentos digitales","proceso de carpeta digital","integracion de carpeta digital","carpeta para titulacion","documentacion de estadia","entrega digital de estadia","requisitos de carpeta digital","que contiene la carpeta digital","expediente de estadia","archivos de estadia","documentacion oficial","carpeta digital uttt","carpeta de titulacion"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo debe nombrarse la Carpeta Digital de Estadía?','La Carpeta Digital debe nombrarse utilizando el nombre completo del estudiante seguido de la matrícula, respetando mayúsculas y minúsculas. Ejemplo: Juan Carlos Martínez García_18301864. Esta nomenclatura permite identificar correctamente la documentación dentro de las carpetas institucionales. Puedes consultar la guía en: https://drive.google.com/file/d/1aaKHWTsOc1ORX1sa6JearcokbC7YINuP/view?usp=sharing.','alumnos',true,'["nombre de la carpeta digital","como nombrar la carpeta digital","nomenclatura de carpeta digital","nombre correcto de carpeta","como llamar la carpeta","nombre de carpeta de estadia","carpeta digital nombre","estructura del nombre","identificar carpeta digital","formato de nombre","nombre de archivos","nomenclatura oficial","como crear la carpeta","nombre institucional","carpeta de drive","nombre de expediente digital","como guardar la carpeta","nombre requerido","carpeta digital ejemplo","como se llama la carpeta"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué documentos deben integrarse en la Carpeta Digital de Estadía?','La Carpeta Digital de Estadía debe integrar, según corresponda, el Acuse de Carta de Presentación, Carta de Aceptación, Carta de Terminación, Carta de Acuerdos de Estadía, Minuta de Acuerdos de Estadía, Plan de Trabajo, Evaluación de Estadía, Reporte de Estadía y Evaluación de la Estadía a Estudiantes. Todos los documentos deben cumplir con los requisitos establecidos en la guía institucional. Puedes consultar la guía en: https://drive.google.com/file/d/1aaKHWTsOc1ORX1sa6JearcokbC7YINuP/view?usp=sharing.','alumnos',true,'["documentos de carpeta digital","que documentos debo subir","archivos de carpeta digital","requisitos de carpeta digital","documentacion de estadia","que contiene la carpeta digital","expediente digital","documentos requeridos","archivos obligatorios","papeles de estadia","documentacion para titulacion","que integrar en carpeta","contenido de carpeta digital","documentos de titulacion","requisitos documentales","expediente de estadia","archivos obligatorios","carpeta de drive estadia","documentacion oficial","formatos de estadia"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo debe nombrarse el archivo de Acuse de Carta de Presentación?','El archivo PDF del Acuse de Carta de Presentación debe nombrarse utilizando el nombre completo del estudiante, matrícula y la palabra Acuse. Ejemplo: Juan Carlos Martínez García_18301864_Acuse. Es importante respetar la nomenclatura establecida para facilitar la identificación y validación de la documentación. Puedes consultar la guía en: https://drive.google.com/file/d/1aaKHWTsOc1ORX1sa6JearcokbC7YINuP/view?usp=sharing.','alumnos',true,'["acuse carta de presentacion","nombre del acuse","nomenclatura del acuse","como nombrar el acuse","archivo acuse","acuse pdf","nombre del archivo acuse","acuse de estadia","formato del acuse","nombre correcto del acuse","archivo de presentacion","acuse carta presentacion","identificar acuse","como guardar el acuse","nombre del documento","pdf acuse","nomenclatura oficial","acuse digital","documento acuse","archivo oficial acuse"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral'); 
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué requisitos debe cumplir la Carta de Aceptación para integrarse a la Carpeta Digital?','La Carta de Aceptación debe integrarse en formato PDF con la nomenclatura Nombre Completo_Matrícula_Aceptación. Además, debe estar fechada como máximo 15 días posteriores a la fecha de inicio de la estadía y contar con firma autógrafa del responsable correspondiente. No se aceptan firmas digitales. Puedes consultar la guía en: https://drive.google.com/file/d/1aaKHWTsOc1ORX1sa6JearcokbC7YINuP/view?usp=sharing. Para más información puedes acudir con tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["requisitos carta de aceptacion","carta de aceptacion carpeta digital","aceptacion pdf","firma de carta de aceptacion","aceptacion con firma autografa","aceptacion digital","fecha de carta de aceptacion","como subir carta de aceptacion","archivo aceptacion","nomenclatura aceptacion","carta aceptacion estadia","documento aceptacion","requisitos de aceptacion","aceptacion en drive","aceptacion firmada","aceptacion oficial","archivo de aceptacion","subir carta aceptacion","aceptacion de estadia","documento de aceptacion"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué requisitos debe cumplir la Carta de Terminación para integrarse a la Carpeta Digital?','La Carta de Terminación debe integrarse en formato PDF con la nomenclatura Nombre Completo_Matrícula_Terminación. Debe estar fechada al término de la estadía conforme al calendario escolar autorizado y contar con firma autógrafa del responsable correspondiente. No se aceptan firmas digitales. Puedes consultar la guía en: https://drive.google.com/file/d/1aaKHWTsOc1ORX1sa6JearcokbC7YINuP/view?usp=sharing.','alumnos',true,'["requisitos carta de terminacion","carta de terminacion carpeta digital","terminacion pdf","firma de carta de terminacion","terminacion con firma autografa","terminacion digital","fecha de carta de terminacion","como subir carta de terminacion","archivo terminacion","nomenclatura terminacion","carta terminacion estadia","documento terminacion","requisitos de terminacion","terminacion en drive","terminacion firmada","terminacion oficial","archivo de terminacion","subir carta terminacion","terminacion de estadia","documento de terminacion"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué cuidados debo tener al integrar la Minuta de Acuerdos de Estadía?','Al integrar la Minuta de Acuerdos de Estadía debes verificar que el título del proyecto sea exactamente el mismo en toda la documentación oficial, incluyendo la Minuta, Plan de Trabajo, Reporte de Estadía, Carta de Terminación y Evaluación de Estadía. Si existen inconsistencias, la documentación podrá ser rechazada y el estudiante no podrá continuar con su trámite de titulación. Puedes consultar la guía en: https://drive.google.com/file/d/1aaKHWTsOc1ORX1sa6JearcokbC7YINuP/view?usp=sharing.','alumnos',true,'["minuta de acuerdos","titulo del proyecto","consistencia del proyecto","nombre del proyecto","errores en minuta","minuta carpeta digital","documentacion consistente","proyecto igual en documentos","requisitos de minuta","minuta de estadia","titulo del reporte","nombre del reporte","validacion de minuta","integracion de minuta","minuta en drive","documentacion de titulacion","coincidencia de documentos","revision de minuta","minuta oficial","cuidados de la minuta"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué requisitos debe cumplir el Plan de Trabajo para integrarse a la Carpeta Digital?','El Plan de Trabajo debe integrarse en formato PDF con la nomenclatura Nombre Completo_Matrícula_Plan de Trabajo. Además, es importante requisitar todos los apartados del formato, incluyendo el espacio correspondiente a requerimientos. Puedes consultar la guía en: https://drive.google.com/file/d/1aaKHWTsOc1ORX1sa6JearcokbC7YINuP/view?usp=sharing.','alumnos',true,'["plan de trabajo carpeta digital","requisitos del plan de trabajo","plan de trabajo pdf","plan de trabajo estadia","como subir plan de trabajo","archivo plan de trabajo","nomenclatura plan de trabajo","formato plan de trabajo","plan de trabajo en drive","requerimientos del plan","apartados del plan","documento plan de trabajo","plan de trabajo oficial","integracion de plan","plan de trabajo digital","archivo oficial","plan de trabajo requisitos","subir plan de trabajo","documentacion de estadia","plan de actividades"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué requisitos debe cumplir la Evaluación de Estadía para integrarse a la Carpeta Digital?','La Evaluación de Estadía debe integrarse en formato PDF con la nomenclatura Nombre Completo_Matrícula_Evaluación. La calificación final debe calcularse y registrarse sin decimales. Además, todas las firmas deben ser autógrafas, ya que no se aceptan firmas digitales. Puedes consultar la guía en: https://drive.google.com/file/d/1aaKHWTsOc1ORX1sa6JearcokbC7YINuP/view?usp=sharing. Para más información puedes acudir con tu asesor académico, Dirección de Carrera o comunicarte con el Departamento de Estadías e Inserción Laboral al correo practicas@uttt.edu.mx o al teléfono 773 732 9100 extensiones 209 o 108.','alumnos',true,'["evaluacion de estadia","requisitos evaluacion","evaluacion carpeta digital","calificacion de estadia","evaluacion pdf","firma en evaluacion","evaluacion con firma autografa","evaluacion digital","subir evaluacion","archivo evaluacion","nomenclatura evaluacion","documento evaluacion","calificacion sin decimales","evaluacion oficial","evaluacion de proyecto","evaluacion en drive","requisitos de evaluacion","evaluacion firmada","archivo oficial evaluacion","formato evaluacion"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué requisitos debe cumplir el Reporte de Estadía para integrarse a la Carpeta Digital?','El Reporte de Estadía debe integrarse en formato PDF con la nomenclatura Nombre Completo_Matrícula_Reporte. La carátula únicamente debe contener las firmas autorizadas del asesor académico y del asesor industrial o responsable correspondiente, y dichas firmas deben ser autógrafas. Puedes consultar la guía en: https://drive.google.com/file/d/1aaKHWTsOc1ORX1sa6JearcokbC7YINuP/view?usp=sharing.','alumnos',true,'["reporte de estadia carpeta digital","requisitos del reporte","reporte pdf","caratula del reporte","firmas del reporte","asesor academico reporte","asesor industrial reporte","reporte firmado","reporte digital","subir reporte","archivo reporte","nomenclatura reporte","reporte oficial","integracion del reporte","documento reporte","reporte en drive","reporte de proyecto","requisitos del documento","firmas autografas reporte","archivo oficial reporte"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Puedo modificar los formatos oficiales utilizados en la Carpeta Digital?','No. Los formatos oficiales utilizados en la Carpeta Digital no pueden modificarse. No está permitido alterar el formato, tipo de letra, fecha de revisión, códigos, estructura o cualquier otro elemento oficial. Los documentos que no cumplan con los requisitos de calidad y forma establecidos no serán aceptados. Puedes consultar la guía en: https://drive.google.com/file/d/1aaKHWTsOc1ORX1sa6JearcokbC7YINuP/view?usp=sharing.','alumnos',true,'["puedo modificar formatos","modificar formatos oficiales","cambiar formato de documentos","editar formatos oficiales","modificar tipo de letra","cambiar codigo del formato","alterar documentos oficiales","modificar plantilla","editar formato institucional","cambiar estructura del formato","formatos oficiales estadia","documentos oficiales","modificacion de formatos","requisitos de calidad","formatos de carpeta digital","puedo editar formatos","personalizar formatos","cambiar revision del formato","formato institucional","documentacion oficial"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Quién es responsable de la integración correcta de la Carpeta Digital de Estadía?','La integración de la Carpeta Digital y la generación de los documentos son responsabilidad absoluta del estudiante. El asesor académico supervisa la correcta integración y verifica que la documentación cumpla con los requisitos de fondo y forma establecidos institucionalmente. Puedes consultar la guía en: https://drive.google.com/file/d/1aaKHWTsOc1ORX1sa6JearcokbC7YINuP/view?usp=sharing.','alumnos',true,'["responsable de la carpeta digital","quien integra la carpeta digital","responsabilidad del estudiante","integracion de documentos","responsable de estadia","asesor academico carpeta digital","quien sube los documentos","responsabilidad de la carpeta","documentacion de estadia","integracion correcta","responsable del expediente","estudiante responsable","quien entrega la carpeta","seguimiento de documentos","supervision del asesor","responsabilidad documental","proceso de integracion","carpeta digital de estadia","responsable de archivos","gestion de documentos"]'::jsonb,'Maricela Fernanda Estefanía Ávila Hernández','Jefe de departamento','Departamento de Estadías e Inserción Laboral');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Aún hay fichas disponibles para ingresar a la UTTT?','La disponibilidad de fichas puede variar durante cada proceso de admisión y depende del programa educativo seleccionado. Para conocer información actualizada sobre disponibilidad de fichas, fechas de registro o espacios disponibles, te recomendamos comunicarte directamente con el Departamento de Ingreso y Captación al correo [comunicacion@uttt.edu.mx](mailto:comunicacion@uttt.edu.mx), al teléfono 773 732 9100 extensiones 248 y 256 o al WhatsApp 773 680 1596.','aspirantes',true,'["aun hay fichas","todavia hay fichas","hay fichas disponibles","siguen dando fichas","todavia puedo sacar ficha","aun puedo registrarme","hay lugares disponibles","hay espacios disponibles","quedan fichas","quedan lugares","puedo obtener ficha","siguen abiertas las fichas","hay cupo disponible","todavia aceptan aspirantes","hay disponibilidad de fichas","puedo hacer mi ficha","aun puedo entrar","siguen las inscripciones","hay vacantes","todavia hay cupo","se agotaron las fichas","todavia puedo inscribirme","hay lugares en la universidad","aun aceptan alumnos","siguen recibiendo aspirantes","hay espacio para ingresar","todavia puedo entrar a la uttt","siguen abiertas las convocatorias","hay fichas para nuevo ingreso","quedan espacios","aun hay registro","todavia puedo aplicar","hay admisiones abiertas","todavia puedo sacar mi ficha","hay fichas para ingresar","siguen disponibles las fichas","hay lugar en alguna carrera","todavia puedo registrarme en linea","hay oportunidades de ingreso","hay cupo en la uttt","puedo participar en la convocatoria","hay fichas vigentes","quedan fichas de admision","hay disponibilidad para nuevo ingreso","siguen los registros","hay lugares para aspirantes","todavia puedo solicitar ficha","hay inscripciones abiertas","puedo registrarme como aspirante","aun puedo obtener una ficha"]'::jsonb,'Brenda Argüelles','Jefe de departamento','Departamento de Ingreso y Captación');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué carreras tienen fichas o lugares disponibles actualmente?','La disponibilidad de fichas y espacios puede variar de acuerdo con la demanda de cada programa educativo durante el proceso de admisión. Para conocer qué carreras cuentan con lugares disponibles, así como información sobre cambios de carrera, registros o disponibilidad de fichas, comunícate con el Departamento de Ingreso y Captación al correo [comunicacion@uttt.edu.mx](mailto:comunicacion@uttt.edu.mx), al teléfono 773 732 9100 extensiones 248 y 256 o al WhatsApp 773 680 1596.','aspirantes',true,'["que carreras tienen lugares","que carreras tienen fichas","carreras disponibles","carreras con cupo","que carreras tienen espacio","que carreras puedo estudiar","ingenieria industrial ya no tiene lugar","que carreras siguen disponibles","programas educativos disponibles","carreras abiertas","que opciones hay disponibles","que carreras tienen vacantes","hay lugar en otra carrera","carreras con disponibilidad","que carrera tiene fichas","cuales carreras tienen espacio","carreras para nuevo ingreso","que carreras tienen cupo","disponibilidad por carrera","que programas tienen fichas","ingenieria industrial sin cupo","ya no hay fichas para mi carrera","que carrera me recomiendan","que carreras siguen aceptando alumnos","hay espacio en alguna carrera","carreras con lugares disponibles","opciones de carrera disponibles","que carreras tienen admision abierta","puedo cambiar de carrera","en que carrera hay lugar","que carreras estan disponibles","carreras con fichas disponibles","carreras para aspirantes","que programas tienen disponibilidad","hay lugar en ingenieria","hay lugar en licenciatura","carreras con vacantes disponibles","que puedo estudiar en la uttt","oferta educativa disponible","que carreras tienen registro abierto","hay cupo en alguna carrera","puedo ingresar a otra carrera","que carreras tienen lugares libres","cuales siguen disponibles","carreras con espacios","programas educativos con cupo","que carreras aceptan aspirantes","disponibilidad de programas","que carreras tienen admisiones","carreras disponibles actualmente"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe de departamento','Departamento de Ingreso y Captación');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debo saber sobre la Licenciatura en Médico Cirujano y Partero de la UTTT?','La Licenciatura en Médico Cirujano y Partero de la Universidad Tecnológica de Tula-Tepeji se ofrece en sistema escolarizado. Para el periodo enero-abril 2027 se encuentran disponibles 70 lugares para las personas aspirantes que obtengan los mejores puntajes en el proceso de selección. El costo de la ficha es de $587.00 MXN. El proceso de admisión contempla preregistro, evaluación de conocimientos, entrevista, curso propedéutico e inscripción. El preregistro puede realizarse en https://uttt.edu.mx/prefichas. Para dudas relacionadas con la Licenciatura en Médico Cirujano y Partero, proceso de admisión, disponibilidad de lugares, registro o documentación, comunícate con el Departamento de Ingreso y Captación al correo comunicacion@uttt.edu.mx, al teléfono 773 732 9100 extensiones 248 y 256 o al WhatsApp 773 680 1596.','aspirantes',true,'["licenciatura medico cirujano y partero","medico cirujano y partero","informacion de medico cirujano y partero","quiero estudiar medicina","carrera de medicina uttt","informacion de medicina","que es medico cirujano y partero","licenciatura en medicina","medicina uttt","informacion de la carrera de medicina","quiero entrar a medicina","como ingresar a medicina","requisitos para medicina","convocatoria de medicina","proceso de admision medicina","lugares para medicina","cupo para medicina","fichas para medicina","costo ficha medicina","registro para medicina","como estudiar medicina en la uttt","medico cirujano convocatoria","aspirante a medicina","carrera medico cirujano","informacion general de medicina","plan de ingreso medicina","admision medico cirujano","que necesito para medicina","como entrar a medico cirujano","medicina en tula tepeji","licenciatura medico cirujano","estudiar medico cirujano","proceso medico cirujano","medico cirujano requisitos","ficha medico cirujano","registro medico cirujano","lugares medico cirujano","informacion carrera medico cirujano","medico y partero","carrera de medico cirujano y partero","informacion de admision medicina","nuevo ingreso medicina","quiero una ficha para medicina","como registrarme a medicina","medicina escolarizada","carrera de salud uttt","informacion medico cirujano y partero uttt","admisiones medicina","convocatoria medico cirujano y partero","informacion completa de medicina"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe de departamento','Departamento de Ingreso y Captación');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué es la Licenciatura en Médico Cirujano y Partero?','La Licenciatura en Médico Cirujano y Partero es un programa educativo del área de la salud orientado a la formación de profesionales capaces de prevenir, diagnosticar y atender problemas de salud en la población. Para conocer información actualizada sobre el programa educativo, proceso de admisión y convocatoria vigente, comunícate con el Departamento de Ingreso y Captación al correo comunicacion@uttt.edu.mx, al teléfono 773 732 9100 extensiones 248 y 256 o al WhatsApp 773 680 1596.','aspirantes',true,'["que es medico cirujano y partero","que es la carrera de medico cirujano y partero","informacion de medico cirujano y partero","de que trata medico cirujano y partero","que estudia un medico cirujano y partero","que es la licenciatura en medico cirujano y partero","informacion de la carrera de medicina","que es la carrera de medicina","carrera de medicina uttt","medico cirujano y partero uttt","quiero estudiar medicina","que ofrece la carrera de medicina","informacion sobre medicina","licenciatura en medicina uttt","que hace un medico cirujano","de que trata medicina","carrera medico cirujano","medico cirujano informacion","que es medicina en la uttt","quiero informacion de medicina"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe de departamento','Departamento de Ingreso y Captación');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cuántos lugares están disponibles para ingresar a Médico Cirujano y Partero?','Para el proceso de admisión correspondiente a la Licenciatura en Médico Cirujano y Partero se encuentran disponibles 70 lugares para las personas aspirantes que obtengan los mejores resultados en el proceso de selección. Para información actualizada sobre disponibilidad de lugares, comunícate con el Departamento de Ingreso y Captación al correo comunicacion@uttt.edu.mx, al teléfono 773 732 9100 extensiones 248 y 256 o al WhatsApp 773 680 1596.','aspirantes',true,'["cuantos lugares hay para medico cirujano","cuantos lugares hay para medicina","cuantos lugares tiene medico cirujano y partero","cuantos alumnos aceptan en medicina","cupo para medico cirujano","lugares disponibles para medicina","cuantos aceptan en medico cirujano","espacios para medicina","cuantos entran a medicina","disponibilidad de lugares medicina","cupo medico cirujano y partero","lugares medico cirujano","cuantos estudiantes aceptan en medicina","hay cupo para medicina","lugares para la carrera de medicina","cuantos lugares quedan en medicina","hay lugares para medico cirujano","espacios disponibles en medicina","medico cirujano tiene cupo","cuantas fichas hay para medicina"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe de departamento','Departamento de Ingreso y Captación');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cuál es el costo de la ficha para Médico Cirujano y Partero?','El costo de la ficha para la Licenciatura en Médico Cirujano y Partero es de $587.00 MXN. Para información actualizada sobre pagos, proceso de admisión o convocatoria, comunícate con el Departamento de Ingreso y Captación al correo comunicacion@uttt.edu.mx, al teléfono 773 732 9100 extensiones 248 y 256 o al WhatsApp 773 680 1596.','aspirantes',true,'["costo ficha medico cirujano","precio ficha medicina","cuanto cuesta la ficha de medicina","ficha medico cirujano y partero","cuanto pago para medicina","costo de admision medicina","precio de la ficha medico cirujano","cuanto cuesta entrar a medicina","ficha para medicina costo","valor de ficha medicina","cuota de admision medicina","precio de registro medicina","cuanto cuesta la convocatoria medicina","costo de la carrera de medicina ingreso","precio ficha medico cirujano y partero","cuanto vale la ficha de medicina","cuanto cuesta registrarse a medicina","cuanto pago por medicina","precio de la preficha medicina","ficha medicina precio"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe de departamento','Departamento de Ingreso y Captación');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Dónde realizo mi preregistro para Médico Cirujano y Partero?','El preregistro para la Licenciatura en Médico Cirujano y Partero se realiza a través del portal https://uttt.edu.mx/prefichas. Si presentas problemas durante tu registro o necesitas orientación sobre el proceso de admisión, comunícate con el Departamento de Ingreso y Captación al correo comunicacion@uttt.edu.mx, al teléfono 773 732 9100 extensiones 248 y 256 o al WhatsApp 773 680 1596.','aspirantes',true,'["preregistro medico cirujano","registro medicina","donde me registro para medicina","como registrarme en medico cirujano","registro medico cirujano y partero","inscripcion medicina","proceso de registro medicina","preficha medicina","prefichas medico cirujano","registro de aspirantes medicina","como sacar ficha para medicina","donde sacar ficha medicina","registro carrera de medicina","registro nuevo ingreso medicina","inscribirme a medicina","como hacer mi registro para medicina","donde hago mi preregistro","link de registro medicina","pagina de registro medicina","registro para medico cirujano"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe de departamento','Departamento de Ingreso y Captación');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué requisitos debo cumplir para aspirar a Médico Cirujano y Partero?','Para participar en el proceso de admisión de la Licenciatura en Médico Cirujano y Partero es necesario haber concluido el bachillerato. Preferentemente se recomienda contar con formación en el área de ciencias de la salud. Además, deberás cumplir con los requisitos y etapas establecidas en la convocatoria vigente. Para más información comunícate con el Departamento de Ingreso y Captación al correo comunicacion@uttt.edu.mx, al teléfono 773 732 9100 extensiones 248 y 256 o al WhatsApp 773 680 1596.','aspirantes',true,'["requisitos para medicina","requisitos medico cirujano","que necesito para medicina","como entrar a medicina","requisitos de ingreso medicina","que piden para medico cirujano","documentos para medicina","requisitos medico cirujano y partero","que necesito para estudiar medicina","admision medicina requisitos","requisitos para la carrera de medicina","que ocupan para medicina","puedo entrar a medicina","ingreso a medico cirujano","requisitos para aspirar a medicina","que se necesita para medico cirujano","condiciones para entrar a medicina","bachillerato para medicina","requisitos academicos medicina","que necesito para registrarme a medicina"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe de departamento','Departamento de Ingreso y Captación');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cuándo iniciarán clases de la Licenciatura en Médico Cirujano y Partero?','De acuerdo con la convocatoria, la Licenciatura en Médico Cirujano y Partero iniciará actividades académicas en el periodo enero-abril de 2027. Para conocer fechas actualizadas o cualquier cambio relacionado con el calendario escolar, comunícate con el Departamento de Ingreso y Captación al correo comunicacion@uttt.edu.mx, al teléfono 773 732 9100 extensiones 248 y 256 o al WhatsApp 773 680 1596.','aspirantes',true,'["cuando inicia medicina","inicio de clases medicina","cuando empiezan clases de medicina","fecha de inicio medicina","cuando entra medico cirujano","inicio de medico cirujano y partero","cuando inicia medico cirujano","calendario medicina","fecha de clases medicina","inicio de semestre medicina","cuando comienza medicina","cuando abre medicina","inicio de actividades medicina","fecha de ingreso medicina","medico cirujano inicio","inicio de carrera medicina","cuando arranca medicina","inicio escolar medicina","cuando estudiare medicina","fecha de inicio medico cirujano"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe de departamento','Departamento de Ingreso y Captación');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo es el proceso de selección para ingresar a Médico Cirujano y Partero?','El proceso de selección para la Licenciatura en Médico Cirujano y Partero contempla diversas etapas, entre ellas preregistro, evaluación de conocimientos, entrevista, curso propedéutico e inscripción. Es importante cumplir con cada una de las etapas establecidas en la convocatoria. Para más información comunícate con el Departamento de Ingreso y Captación al correo comunicacion@uttt.edu.mx, al teléfono 773 732 9100 extensiones 248 y 256 o al WhatsApp 773 680 1596.','aspirantes',true,'["proceso de seleccion medicina","como entrar a medicina","admision medicina","proceso medico cirujano","etapas de medicina","seleccion medico cirujano","como ingresar a medico cirujano","proceso de admision medicina","pasos para medicina","ingreso a medicina","evaluacion medicina","entrevista medicina","curso propedeutico medicina","seleccion medico cirujano y partero","proceso de ingreso medicina","como me seleccionan en medicina","admisiones medicina","convocatoria medicina proceso","requisitos de seleccion medicina","etapas medico cirujano"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe de departamento','Departamento de Ingreso y Captación');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué incluye la evaluación de conocimientos para Médico Cirujano y Partero?','La evaluación de conocimientos forma parte del proceso de selección para la Licenciatura en Médico Cirujano y Partero. Para conocer el contenido, temario, modalidad de aplicación o información específica sobre esta evaluación, te recomendamos consultar la convocatoria vigente o comunicarte con el Departamento de Ingreso y Captación al correo comunicacion@uttt.edu.mx, al teléfono 773 732 9100 extensiones 248 y 256 o al WhatsApp 773 680 1596.','aspirantes',true,'["examen medicina","evaluacion medicina","temario medicina","que viene en el examen de medicina","prueba de medicina","evaluacion de conocimientos medicina","examen medico cirujano","que incluye el examen de medicina","temas del examen medicina","guia de estudio medicina","examen de admision medicina","evaluacion medico cirujano","contenido del examen medicina","prueba medico cirujano y partero","que estudiar para medicina","como es el examen medicina","preguntas del examen medicina","evaluacion de ingreso medicina","temario medico cirujano","examen para medico cirujano"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe de departamento','Departamento de Ingreso y Captación');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué pasa si no asisto a alguna etapa del proceso de selección?','Las personas aspirantes deben cumplir con todas las etapas del proceso de selección establecidas en la convocatoria. No asistir a alguna de ellas puede impedir la continuidad dentro del proceso de admisión. Para aclarar cualquier situación particular, comunícate con el Departamento de Ingreso y Captación al correo comunicacion@uttt.edu.mx, al teléfono 773 732 9100 extensiones 248 y 256 o al WhatsApp 773 680 1596.','aspirantes',true,'["si falto al examen de medicina","si no voy a la entrevista medicina","si no asisto al propedeutico","faltar al proceso de medicina","que pasa si falto medicina","no fui al examen medicina","no fui a la entrevista medicina","pierdo mi lugar en medicina","faltar a seleccion medicina","inasistencia medicina","ausencia en medicina","no puedo asistir al examen","que pasa si no voy medicina","faltar al curso propedeutico","inasistencia medico cirujano","si no asisto al proceso","ausencia medico cirujano","pierdo la admision medicina","falta a etapa de seleccion","proceso de medicina inasistencia"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe de departamento','Departamento de Ingreso y Captación');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo me notificarán las fechas y resultados del proceso de selección?','Las fechas, avisos y resultados relacionados con el proceso de selección de la Licenciatura en Médico Cirujano y Partero se notificarán a través de los medios oficiales establecidos en la convocatoria, principalmente mediante el correo electrónico proporcionado por la persona aspirante durante su registro. Para más información comunícate con el Departamento de Ingreso y Captación al correo comunicacion@uttt.edu.mx, al teléfono 773 732 9100 extensiones 248 y 256 o al WhatsApp 773 680 1596.','aspirantes',true,'["resultados medicina","como saber si quede en medicina","notificacion medicina","correo de resultados medicina","cuando salen resultados medicina","avisos medicina","fechas medicina","resultados medico cirujano","como me avisaran medicina","publicacion de resultados medicina","notificaciones medicina","resultado de admision medicina","cuando me notifican medicina","informacion de resultados medicina","seguimiento medicina","correo de admision medicina","fechas del proceso medicina","resultados medico cirujano y partero","consulta de resultados medicina","avisos de medicina"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe de departamento','Departamento de Ingreso y Captación');  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué posgrados ofrece actualmente la UTTT?','La Universidad Tecnológica de Tula-Tepeji ofrece actualmente programas de posgrado orientados al desarrollo profesional y directivo. Entre ellos se encuentran la Maestría en Alta Dirección de las Organizaciones y la Maestría en Economía Circular con Especialidad en Proyectos Sustentables. Las personas interesadas pueden consultar la información completa de los programas y realizar su registro mediante los medios oficiales de la universidad. Registro de aspirantes: https://docs.google.com/forms/d/e/1FAIpQLScN9OWSgzEdos3xf5_AFkFsD78NnlOAqnwlGF_pmAGs5NPi_A/viewform. Para más información sobre los programas de posgrado comunícate con el Departamento de Ingreso y Captación.','aspirantes',true,'["posgrados uttt","maestrias uttt","que maestrias ofrece la uttt","posgrados disponibles","oferta de posgrados","estudiar maestria en la uttt","maestrias disponibles","programas de posgrado","posgrados 2026","maestrias 2026","quiero estudiar una maestria","opciones de posgrado","que posgrados hay","que maestrias tienen","posgrado alta direccion","posgrado economia circular","maestrias de la uttt","informacion de posgrados","oferta academica de posgrado","programas de maestria","posgrados universidad tecnologica","maestrias universidad tecnologica","posgrados en tula tepeji","maestrias en tula tepeji","educacion de posgrado","especialidades y maestrias","programas de especializacion","estudios de posgrado","continuar estudiando","maestrias para profesionistas"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe de departamento','Departamento de Ingreso y Captación');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué es la Maestría en Alta Dirección de las Organizaciones?','La Maestría en Alta Dirección de las Organizaciones está orientada a la formación de líderes capaces de dirigir organizaciones con visión estratégica, fortalecer la toma de decisiones, impulsar la innovación y mejorar la competitividad empresarial. Este programa busca desarrollar habilidades gerenciales, financieras y de liderazgo para afrontar los retos actuales de las organizaciones. Puedes consultar información detallada sobre el programa en: https://www.uttt.edu.mx/Posgrados/ebook/AltaDireccion/mobile/index.html. El registro para aspirantes se encuentra disponible en: https://docs.google.com/forms/d/e/1FAIpQLScN9OWSgzEdos3xf5_AFkFsD78NnlOAqnwlGF_pmAGs5NPi_A/viewform. Para más información comunícate con el Departamento de Ingreso y Captación.','aspirantes',true,'["maestria alta direccion","alta direccion de las organizaciones","maestria en alta direccion","posgrado alta direccion","informacion alta direccion","estudiar alta direccion","maestria gerencial","maestria para directivos","maestria administrativa","liderazgo organizacional","direccion de organizaciones","alta direccion uttt","posgrado gerencial","maestria ejecutiva","maestria para gerentes","administracion estrategica","gestion directiva","innovacion empresarial","direccion empresarial","programa alta direccion","que es alta direccion","informacion de la maestria alta direccion","plan de estudios alta direccion","maestria organizacional","alta direccion universidades","posgrado en administracion","maestria para lideres","desarrollo directivo","gestion empresarial","maestria organizacional uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe de departamento','Departamento de Ingreso y Captación');
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué es la Maestría en Economía Circular con Especialidad en Proyectos Sustentables?','La Maestría en Economía Circular con Especialidad en Proyectos Sustentables está enfocada en la formación de profesionistas capaces de diseñar estrategias de economía circular, evaluar la viabilidad de proyectos sustentables, impulsar soluciones relacionadas con energías renovables y desarrollar modelos de negocio innovadores con enfoque ambiental y de sostenibilidad. Puedes consultar información detallada sobre el programa en: https://www.uttt.edu.mx/Posgrados/ebook/EconomiaCircular/mobile/index.html. El registro para aspirantes se encuentra disponible en: https://docs.google.com/forms/d/e/1FAIpQLScN9OWSgzEdos3xf5_AFkFsD78NnlOAqnwlGF_pmAGs5NPi_A/viewform. Para más información comunícate con el Departamento de Ingreso y Captación.','aspirantes',true,'["maestria economia circular","economia circular","proyectos sustentables","maestria en economia circular","economia circular con especialidad en proyectos sustentables","posgrado economia circular","informacion economia circular","estudiar economia circular","maestria sustentabilidad","maestria ambiental","proyectos sustentables uttt","economia circular uttt","energias renovables","sostenibilidad","desarrollo sustentable","maestria ecologica","gestion ambiental","economia verde","innovacion sustentable","economia circular y sustentabilidad","que es economia circular","especialidad en proyectos sustentables","maestria proyectos sustentables","programa economia circular","posgrado sustentable","medio ambiente","economia circular informacion","maestria de sostenibilidad","proyectos ambientales","economia circular posgrado"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe de departamento','Departamento de Ingreso y Captación');  